INSERT INTO `characters` (`id`, `name`, `element`, `weapon`, `rarity`, `guide_content`, `image_url`, `mat_1`, `mat_2`, `mat_3_tier1`, `mat_3_tier2`, `mat_3_tier3`, `mat_3_tier4`, `hp_base`, `hp_max`, `atk_base`, `atk_max`, `def_base`, `def_max`, `rec_wp_1`, `rec_wp_2`, `rec_wp_3`, `rec_echo_1`, `rec_sonata_1`, `build_1_name`, `build_2_name`, `rec_echo_2`, `rec_sonata_2`, `best_stat_1`, `best_stat_2`, `best_stat_3`, `best_stat_4`, `best_stat_5`) VALUES
(1, 'Sigrika', 'Aero', 'Gauntlets', 5, 'Sigrika in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nSigrika, a student of Startorch Academy and a Resonator of Royan Runes. Determined to live up to others\' expectations and become a true Solsworn, she devotes herself fully to every challenge.', 'sigrika.jpg', 'Our Choice', 'Arithmetic Shell', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 862, 10775, 35, 437, 93, 1136, 'Solsworn Ciphers', 'Blazing Justice', 'Pulsation Bracer', 'Nameless Explorer', 'Sound of True Name', 'Standard Build', NULL, NULL, NULL, 'ATK', 'ATK%', 'Crit. Rate', 'Crit. DMG', 'Energy Regen'),
(2, 'Luuk Herssen', 'Spectro', 'Gauntlets', 5, 'Luuk Herssen in Wuthering Waves is a 5 Stars Spectro character who wields a Gauntlets as their weapon type.\r\n\r\nThe attending physician of Startorch Academy\'s Resonator Nursing Unit, renowned for his keen intellect and unshakable composure. Rumor has it nobody has ever seen him lose control. He is a keen listener adept at dissecting the shadows in a person\'s heart. From the unhealing wound on his hand, golden blood seeps, a substance he can summon to become a blade of utmost precision.', 'luuk_herssen.jpg', 'Suncoveter\'s Reach', 'Edelschnee', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant\r\n', 'Intact Exoswarm Pendant', 824, 10300, 37, 462, 91, 1112, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(3, 'Aemeath', 'Fusion', 'Sword', 5, 'Aemeath in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\nOnce an Exostrider Synchronist of Rabelle College, she is now a digital ghost who sings quietly amongst stars.', 'aemeath.jpg', 'Our Choice', 'Moss Amber', 'LF Exoswarm Core', 'MF Exoswarm Core', 'HF Exoswarm Core', 'FF Exoswarm Core', 882, 11025, 34, 425, 94, 1148, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(4, 'Mornye', 'Fusion', 'Broadblade', 5, 'Mornye in Wuthering Waves is a 5 Stars Fusion character who wields a Broadblade as their weapon type.\r\n\r\nMornye, a Spacetrek Collective Research Institute engineer and a Department of Exostrider Engineering professor at Startorch Academy. Each step on her prosthetic legs carries her toward the stars of her dreams.', 'mornye.jpg', 'Burning Judgment', 'Gemini Spore', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 1230, 15375, 23, 287, 111, 1356, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(5, 'Lynae', 'Spectro', 'Pistols', 5, 'Lynae in Wuthering Waves is a 5 Stars Spectro character who wields a Pistols as their weapon type.\r\n\r\nA Startorch Academy prep student whose head-turning, electric style hides an inner focus as explosive as a coiled spring.', 'lynae.jpg', 'Suncoveter\'s Reach', 'Rimewisp', 'LF Exoswarm Core', 'MF Exoswarm Core', 'HF Exoswarm Core', 'FF Exoswarm Core', 979, 12237, 30, 375, 98, 1197, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(6, 'Buling', 'Electro', 'Rectifier', 4, 'Buling in Wuthering Waves is a 4 Stars Electro character who wields a Rectifier as their weapon type.\r\n\r\nTaoist of Mengzhou, Black Shores Consultant, feng shui master, and veteran forum dweller. Easygoing and well-traveled, Buling will \"bling\" whatever you seek.', 'buling.jpg', 'Blighted Crown of Puppet King', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 850, 10625, 18, 225, 103, 1258, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(7, 'Chisa', 'Havoc', 'Broadblade', 5, 'Chisa in Wuthering Waves is a 5 Stars Havoc character who wields a Broadblade as their weapon type.\r\n\r\n\"Just an ordinary student.\" Calmly, she introduces herself, a faint iridescent shimmer flickering in her eyes. Again, the structures of the world reveal themselves in her vision. Narrowing her eyes, she singles out the very thread that tugs at life itself.', 'chisa.jpg', 'Abyssal Husk', 'Summer Flower', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 862, 10775, 35, 437, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(8, 'Qiuyuan', 'Aero', 'Sword', 5, 'Qiuyuan in Wuthering Waves is a 5 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nFormer senior agent of Mingting\'s Internal Security Agency. Though enmity filled his younger days, loyalty defined his later years. However, scapegoated for a murder, he is now but a blind swordsman wandering the world alone.', 'qiuyuan.jpg', 'Truth in Lies\r\n', 'Wintry Bell', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 979, 12237, 30, 375, 98, 1197, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(9, 'Galbrena', 'Fusion', 'Pistols', 5, 'Galbrena in Wuthering Waves is a 5 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nCold and decisive, she is the \"Discord Slayer\" who hunts across Solaris and the same \"Fiend of Ever-burning Flame\" spoken of in whispers. Now, she serves as a Black Shores Consultant, active across the world.', 'galbrena.jpg', 'Blighted Crown of Puppet King', 'Stone Rose', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 824, 10300, 37, 462, 91, 1112, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(10, 'Iuno', 'Aero', 'Gauntlets', 5, 'Iuno in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nShe is favored by fate under one name, and swept away by it in another. Yet never once has she been defeated, nor has she ever yielded. Now, witness the defiant Priestess. Witness what keeps her striding forward, never to look back. Witness how she walks the intricate web of destiny and becomes the only answer.', 'iuno.jpg', 'Abyssal Husk', 'Sliverglow Bloom', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 842, 10525, 36, 450, 92, 1124, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(11, 'Augusta', 'Electro', 'Broadblade', 5, 'Augusta in Wuthering Waves is a 5 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nEphor of Septimont. The undying sun eternally ablaze, and a banner under which defeat does not exist. She comes. She sees. She conquers. With blade held high, she awaits the next challenger or the fate that claims it cannot be defied.', 'augusta.jpg', 'Blighted Crown of Puppet King', 'Luminous Calendula', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 824, 10300, 37, 462, 91, 1112, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(12, 'Phrolova', 'Havoc', 'Rectifier', 5, 'Phrolova in Wuthering Waves is a 5 Stars Havoc character who wields a Rectifier as their weapon type.\r\n\r\nPhrolova, a Fractsidus Overseer walking the fine line between life and death, an uncanny, deadly conductor. A silent wave of her baton is enough to attune the very frequencies of being and conduct the symphonies of \"souls.\" The music of hers can sculpt a better world or, just as easily, summon a legion to wreak havoc.', 'phrolova.jpg', 'Truth in Lies', 'Afterlife', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 862, 10775, 35, 437, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(13, 'Lupa', 'Fusion', 'Broadblade', 5, 'Lupa in Wuthering Waves is a 5 Stars Fusion character who wields a Broadblade as their weapon type.\r\n\r\nA Gladiator of Septimont, a radiant star of the arena. Fiery and straightforward, Lupa lives like a wild lone wolf. As long as she can savor the adrenaline rush of battle, she doesn\'t mind if that same fire ends up consuming her whole.', 'lupa.jpg', 'Unfading Glory', 'Bloodleaf Viburnum', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 953, 11912, 31, 387, 97, 1185, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(14, 'Cartethyia', 'Aero', 'Sword', 5, 'Cartethyia in Wuthering Waves is a 5 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nCartethyia, the wandering knight who travels across Rinascita. Formerly known as the Blessed Maiden, the vessel of Divinity, and the Queen of Gale and Tide, she went by the name Fleurdelys. Now, she is simply a free and unfettered wandering knight.\r\n\r\n', 'cartethyia.jpg', 'Unfading Glory', 'Bamboo Iris', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 1184, 14800, 25, 312, 50, 611, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(15, 'Ciaccona', 'Aero', 'Pistols', 5, 'Ciaccona in Wuthering Waves is a 5 Stars Aero character who wields a Pistols as their weapon type.\r\n\r\nA wandering bard from Rinascita, Ciaccona. She sings not only for the Divinity, but also for the common folk. She records stories along her journeys, turning them into songs that evoke laughter, emotion, and tears in both the storytellers and the audience.', 'ciaccona.jpg', 'Blazing Bone', 'Golden Fleece', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 979, 12237, 30, 375, 98, 1197, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(16, 'Zani', 'Spectro', 'Gauntlets', 5, 'Zani in Wuthering Waves is a 5 Stars Spectro character who wields a Gauntlets as their weapon type.\r\n\r\nA member of Averardo Vault\'s security team and holder of \"Best Employee\" for longer than she cares to count. She has made plenty of plans for her free time, but for now, her biggest mission is simple: clocking out on time.', 'zani.jpg', 'Platinum Core', 'Sword Acorus', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 862, 10775, 35, 437, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(17, 'Cantarella', 'Havoc', 'Rectifier', 5, 'Cantarella in Wuthering Waves is a 5 Stars Havoc character who wields a Rectifier as their weapon type.\r\n\r\nThe current head of Fisalia, Cantarella, the Bane. A mysterious noblewoman, her beauty as captivating as it is perilous. She resides in a crown-like castle perched atop the mountain, where illusory dreams flow like streams, meticulously spun by her own hands.', 'cantarella.jpg', 'Cleansing Conch\r\n', 'Seaside Cendrelis', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 928, 11600, 32, 400, 90, 1099, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(18, 'Brant', 'Fusion', 'Sword', 5, 'Brant in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\n\r\nBrant, the captain of Rinascita\'s Troupe of Fools, is a free spirit and romantic. Unpredictable and full of life, he is the beating heart of the troupe. On stage, he slips into countless roles, donning new masks to breathe life into every story. Yet beyond the spotlight, he is unwaveringly genuine, offering nothing but true sincerity to those around him.\r\n\r\n', 'brant.jpg', 'Blazing Bone', 'Golden Fleece', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 934, 11675, 30, 375, 107, 1307, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(19, 'Phoebe', 'Spectro', 'Rectifier', 5, 'Phoebe in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nPhoebe, Acolyte of the Order of the Deep, is a young woman of quiet devotion. With a kind heart, she fulfills her duties with unwavering diligence. Her prayers, like the light she carries, offer comfort and peace to all.', 'phoebe.jpg', 'Cleansing Conch', 'Firecracker Jewelweed', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 866, 10825, 33, 412, 103, 1258, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(20, 'Roccia', 'Havoc', 'Gauntlets', 5, 'Roccia in Wuthering Waves is a 5 Stars Havoc character who wields a Gauntlets as their weapon type.\r\n\r\nAssistant, prop master, and improv comedian, Roccia is always there to make sure the Troupe of Fools is at the ready. The Magic Box she carries appears to hold the world, or perhaps she had recreated a world inside the box.', 'roccia.jpg', 'Cleansing Conch', 'Firecracker Jewelweed', 'LF Tidal Residuum', 'MF Tidal Residuum', 'HF Tidal Residuum', 'FF Tidal Residuum', 980, 12250, 30, 375, 98, 1197, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(21, 'Carlotta', 'Glacio', 'Pistols', 5, 'Carlotta in Wuthering Waves is a 5 Stars Glacio character who wields a Pistols as their weapon type.\r\n\r\nThe second daughter of Montelli and an art investor unbound by convention, Carlotta moves seamlessly through social circles and business transactions while quietly handling the family\'s unspeakable \"troubles\" in secret. The blooming of a \"gem,\" the taking of a life—In her own name, she reshapes reality, giving it a new dimension.', 'carlotta.jpg', 'Platinum Core', 'Sword Acorus', 'LF Polygon Core', 'MF Polygon Core', 'HF Polygon Core', 'FF Polygon Core', 996, 12450, 37, 462, 98, 1197, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(22, 'Lumi', 'Electro', 'Broadblade', 4, 'Lumi in Wuthering Waves is a 4 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nNavigator at Lollo Logistics and leader of a transport squad. Born in a mountain village in Yuezhou, Lumi\'s sincere and caring nature brings warmth to everyone around her.', 'lumi.jpg', 'Thundering Tacet Core', 'Terraspawn Fungus', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 680, 8500, 27, 337, 72, 879, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(23, 'Camellya', 'Havoc', 'Sword', 5, 'Camellya in Wuthering Waves is a 5 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nA Bloom Bearer of the Black Shores, Camellya is free-spirited and dangerously charming. She roams Solaris in search of talent, immersing herself in the present and relishing its pleasures, all while remaining true to herself, unburdened by thoughts of the past or future.', 'camellya.jpg', 'Topological Confinement', 'Nova', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 826, 10325, 36, 450, 95, 1161, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(24, 'Youhu', 'Glacio', 'Gauntlets', 4, 'Youhu in Wuthering Waves is a 4 Stars Glacio character who wields a Gauntlets as their weapon type.\r\n\r\nA voluble and whimsical antique appraiser. Known for creating limericks on the spot, she presents her appraisals with flair and precision. She sets up a stall on the street, ensuring antiques find their way to those who truly cherish them.', 'youhu.jpg', 'Topological Confinement', 'Violet Coral', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 798, 9975, 21, 262, 86, 1051, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(25, 'Shorekeeper', 'Spectro', 'Rectifier', 5, 'Shorekeeper in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nThe Shorekeeper, guardian of the Black Shores—this title alone once defined her. But desires, bonds, and emotions… She only began to understand these things after meeting you.', 'shorekeeper.jpg', 'Topological Confinement', 'Nova', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 1337, 16712, 23, 287, 90, 1099, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(26, 'Xiangli Yao', 'Electro', 'Gauntlets', 5, 'Xiangli Yao in Wuthering Waves is a 5 Stars Electro character who wields a Gauntlets as their weapon type.\r\n\r\nPrincipal Investigator at Jinzhou Huaxu Academy, and the Academy\'s youngest multi-disciplinary scientist. A gentle soul with a sharp mind, whose relentless passion for Automata Mechanics always translates into constructive findings and insights.', 'xiangliyao.jpg', 'Hidden Thunder Tacet Core', 'Violet Coral', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 850, 10625, 34, 425, 100, 1222, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(27, 'Zhezhi', 'Glacio', 'Rectifier', 5, 'Zhezhi in Wuthering Waves is a 5 Stars Glacio character who wields a Rectifier as their weapon type.\r\n\r\nAn artist for hire trying to make a living. Reserved and timid, she is not good with words but speaks volumes through her art, where her creations come to life with impossible authenticity.', 'zhezhi.jpg', 'Sound-Keeping Tacet Core', 'Lanternberry', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 980, 12250, 30, 375, 98, 1197, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(28, 'Changli', 'Fusion', 'Sword', 5, 'Changli in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\n\r\nChangli is a counselor serving the Jinzhou Magistrate, and former Secretary-General in the capital. Shrouded in flames, she\'s fated to burn brightly until her final embers. With her fiery determination and strategic mindset, she rises to power, always thinking ahead to reach her ultimate goal.', 'changli.jpg', 'Rage Tacet Core', 'Pavo Plum', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 831, 10387, 37, 462, 90, 1099, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(29, 'Jinhsi', 'Spectro', 'Broadblade', 5, 'Jinhsi in Wuthering Waves is a 5 Stars Spectro character who wields a Broadblade as their weapon type.\r\n\r\nJinhsi, Magistrate of Jinzhou, gently brightens the hopes of her people, like rays of winter sunlight. As the revered Sentinel\'s Appointed Resonator, she displays humility and wholeheartedly commits herself to guiding her people towards a brilliant future.', 'jinhsi.jpg', 'Elegy Tacet Core', 'Loong\'s Pearl', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 866, 10825, 33, 412, 103, 1258, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(30, 'Yinlin', 'Electro', 'Rectifier', 5, 'Yinlin in Wuthering Waves is a 5 Stars Electro character who wields a Rectifier as their weapon type.\r\n\r\nYinlin is a skilled Patroller and powerful Natural Resonator. After being suspended from her duties at the Public Security Bureau, she must now pursue hidden evils in secrecy.', 'yinlin.jpg', 'Group Abomination Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 880, 11000, 32, 400, 105, 1283, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(31, 'Jiyan', 'Aero', 'Broadblade', 5, 'Jiyan in Wuthering Waves is a 5 Stars Aero character who wields a Broadblade as their weapon type.\r\n\r\nJiyan, leader of the Midnight Rangers, acts with swift and resolute righteousness. He possesses the formidable ability to conjure a powerful Qingloong from the winds, making him invincible on the battlefield.', 'jiyan.jpg', 'Roaring Rock Fist', 'Pecok Flower', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 839, 10487, 35, 437, 97, 1185, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(32, 'Rover (Aero)', 'Aero', 'Sword', 5, 'Rover (Aero) in Wuthering Waves is a 5 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_aero.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(33, 'Rover (Havoc)', 'Havoc', 'Sword', 5, 'Rover (Havoc) in Wuthering Waves is a 5 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_havoc.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(34, 'Rover (Spectro)', 'Spectro', 'Sword', 5, 'Rover (Spectro) in Wuthering Waves is a 5 Stars Spectro character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_spectro.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(35, 'Jianxin', 'Aero', 'Gauntlets', 5, 'Jianxin in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nJianxin, a Taoist monk and successor of Fengyiquan, has dedicated her life to mastering the ultimate martial art. With the power to harness and transform environmental Chi, she can create protective barriers that purify both body and mind.', 'jianxin.jpg', 'Roaring Rock Fist', 'Lanternberry', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 1129, 14112, 27, 337, 92, 1124, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(36, 'Calcharo', 'Electro', 'Broadblade', 5, 'Calcharo in Wuthering Waves is a 5 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nLeader of the \"Ghost Hounds,\" an international mercenary group. Ruthless, vengeful, unforgiving. His Forte allows him to summon a special Tacet Discord to assist his assault on the targets. A potential client must be mindful of the price to pay before making him an offer.', 'calcharo.jpg', 'Thundering Tacet Core', 'Iris', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 840, 10500, 35, 437, 97, 1185, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(37, 'Encore', 'Fusion', 'Rectifier', 5, 'Encore in Wuthering Waves is a 5 Stars Fusion character who wields a Rectifier as their weapon type.\r\n\r\nA girl accompanied by one black and one white Wooly. Encore, consultant from the Black Shores, dreams of creating happy stories with candies, fairy tales, and her imagination.', 'encore.jpg', 'Rage Tacet Core', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 841, 10512, 34, 425, 102, 1246, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(38, 'Lingyang', 'Glacio', 'Gauntlets', 5, 'Lingyang in Wuthering Waves is a 5 Stars Glacio character who wields a Gauntlets as their weapon type.\r\n\r\nAn enthusiastic, brave member of the Liondance Troupe in Jinzhou, Lingyang is a sincere, compassionate visitor of the human community with incredible physical abilities, whose interest in humans easily shows. With his unique style, he embodies the spirit of Liondance.', 'lingyang.jpg', 'Sound-Keeping Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 831, 10387, 35, 437, 99, 1209, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(39, 'Verina', 'Spectro', 'Rectifier', 5, 'Verina in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nWith an extensive knowledge of botany, Verina is always solicitous, always smiling, and always wishing for every flower to be blessed with the miracle of life.', 'verina.jpg', 'Elegy Tacet Core', 'Belle Poppy', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 1139, 14237, 27, 337, 90, 1099, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(40, 'Aalto', 'Aero', 'Pistols', 4, 'Aalto in Wuthering Waves is a 4 Stars Aero character who wields a Pistols as their weapon type.\r\n\r\nAalto is an enigmatic Information Broker, known for his elusive nature and welcoming smile. Underneath the facade, he is closely affiliated with the Black Shores. Rumor has it he\'ll provide any information at the right price.', 'aalto.jpg', 'Roaring Rock Fist', 'Wintry Bell', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 788, 9850, 21, 262, 88, 1075, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(41, 'Yangyang', 'Aero', 'Sword', 4, 'Yangyang in Wuthering Waves is a 4 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nYangyang is an Outrider of the Midnight Rangers. Once sheltered, now a fighter. She soars with the wind to protect others, like a skylark in flight.', 'yangyang.jpg', 'Roaring Rock Fist', 'Wintry Bell', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 816, 10200, 20, 250, 90, 1099, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(42, 'Yuanwu', 'Electro', 'Gauntlets', 4, 'Yuanwu in Wuthering Waves is a 4 Stars Electro character who wields a Gauntlets as their weapon type.\r\n\r\nYuanwu owns a boxing gym where he teaches Leihuangquan and health management. He is well-respected in the community for his cordial demeanor and pleasant temperament.', 'yuanwu.jpg', 'Hidden Thunder Tacet Core', 'Terraspawn Fungus', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 682, 8525, 18, 225, 134, 1637, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(43, 'Chixia', 'Fusion', 'Pistols', 4, 'Chixia in Wuthering Waves is a 4 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nChixia is a spirited young Jinzhou Patroller who lights up the streets of Jinzhou. She\'s always ready to be the hero someone needs. She fuses such passion into the bullets that blast out of her fingertips.', 'chixia.jpg', 'Rage Tacet Core', 'Belle Poppy', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 727, 9087, 24, 300, 78, 953, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(44, 'Mortefi', 'Fusion', 'Pistols', 4, 'Mortefi in Wuthering Waves is a 4 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nMortefi, a skilled expert in Applied Tacetite Study and a member of the Academy’s Department of Safety, possesses the unique ability to transform his accumulated frustration into fiery flames. From a burning wrath that consumes all, the red dragon shall descend.', 'mortefi.jpg', 'Rage Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 802, 10025, 20, 250, 93, 1136, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(45, 'Sanhua', 'Glacio', 'Sword', 4, 'Sanhua in Wuthering Waves is a 4 Stars Glacio character who wields a Sword as their weapon type.\r\n\r\nThe bodyguard of Jinzhou\'s Magistrate, known for having an icy personality. Once regarded as the Asura of Calamity, Sanhua is now a taciturn guardian. She has learned to maintain inner calmness amidst the chaotic frequencies, and the things that once frightened her now fuel her determination.', 'sanhua.jpg', 'Sound-Keeping Tacet Core', 'Wintry Bell', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 805, 10062, 22, 275, 77, 941, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(46, 'Baizhi', 'Glacio', 'Rectifier', 4, 'Baizhi in Wuthering Waves is a 4 Stars Glacio character who wields a Rectifier as their weapon type.\r\n\r\nBaizhi is a researcher in Remnant Ecoacoustics. Baizhi\'s once unfulfilled wish has now manifested as her loyal companion. The Remnant Creature You\'tan is her source of healing powers, and a lifelong research focus.', 'baizhi.jpg', 'Sound-Keeping Tacet Core', 'Lanternberry', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 1025, 12812, 17, 212, 82, 1002, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(47, 'Danjin', 'Havoc', 'Sword', 4, 'Danjin in Wuthering Waves is a 4 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nWith a vengeful blade of condensed blood in hand, Ranger Danjin hunts down thieves and bandits for retribution. She journeys to distant lands in pursuit of justice.', 'danjin.jpg', 'Strife Tacet Core', 'Belle Poppy', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 755, 9437, 21, 262, 94, 1148, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
(48, 'Taoqi', 'Havoc', 'Broadblade', 4, 'Taoqi in Wuthering Waves is a 4 Stars Havoc character who wields a Broadblade as their weapon type.\r\n\r\nTaoqi is the director of border defense at the Ministry of Development. Despite her seemingly laid-back demeanor, she consistently proves to be a dependable and supportive individual, always lending her hand to those in need. Taoqi is not only a reliable colleague, but also a trustworthy friend that people can confide in.', 'taoqi.jpg', 'Gold-Dissolving Feather', 'Iris', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 716, 8950, 18, 225, 128, 1564, NULL, NULL, NULL, NULL, NULL, 'Standard Build', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `echoes` (`id`, `name`, `cost`, `sonata_effect`, `image_url`, `description`) VALUES
(2, 'Nightmare: Feilian Beringal', 4, 'Sierra Gale', 'Nightmare_Feilian_Beringal.jpg', 'Summon a Nightmare: Feilian Beringal to attack enemies, dealing 164.16% Aero DMG. The remaining Whirlwind Beam will continuously attack surrounding enemies up to 5 times, each dealing 21.89% Aero DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Aero DMG Bonus and 12.00% Heavy Attack DMG Bonus. \r\n\r\nCD: 20s.'),
(4, 'Nightmare: Impermanence Heron', 4, 'Midnight Veil', 'Nightmare_Impermanence_Heron.jpg', 'Transform into Nightmare: Impermanence Heron and deliver up to 10 consecutive strikes to surrounding enemies, each dealing 40.50% Havoc DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Havoc DMG Bonus and 12.00% Heavy Attack DMG Bonus. \r\n\r\nCD: 25s.'),
(6, 'Nightmare: Mourning Aix', 4, 'Eternal Radiance', 'Nightmare_Mourning_Aix.jpg', 'Summon a Nightmare: Mourning Aix to attack surrounding enemies, dealing 273.60% Spectro DMG. DMG dealt to enemies inflicted by Spectro Frazzle is increased by 100.00%. The Resonator with this Echo equipped in their main slot gains 12.00% Spectro DMG Bonus.\r\n\r\nCD: 20s.'),
(7, 'Lampylumen Myriad', 4, 'Freezing Frost', 'Lampylumen_Myriad.jpg', 'Transform into Lampylumen Myriad. Perform up to 3 consecutive attacks. Unleash a freezing shock by performing consecutive forward strikes, with the initial two strikes inflicting 200.16% and 200.16% Glacio DMG respectively, and the final strike dealing 266.88% Glacio DMG. Enemies will be frozen on hit. Each shock increases the current character\'s Glacio DMG by 4.00% and Resonance Skill DMG dealt by 4.00% for 15s, stacking up to 3 times \r\n\r\nCD: 20s'),
(9, 'Nightmare: Crownless', 4, 'Havoc Eclipse', 'Nightmare_Crownless.jpg', 'Transform into Nightmare: Crownless and attack enemies in front, dealing 264.60% Havoc DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Havoc DMG Bonus and 12.00% Basic Attack DMG Bonus. This skill has 3 initial charges, replenished once every 12s, max 3 charges. When Nightmare: Crownless hits a target, DMG dealt by this skill is increased by 20.00%. This effect lasts for 2s and does not stack. \r\n\r\nCD: 12s.'),
(11, 'Dragon of Dirge', 4, 'Tidebreaking Courage', 'Dragon_of_Dirge.jpg', 'Transform into Dragon of Dirge and summon a Grief Rift lasting for 5s. Periodically deal 36.81% Fusion DMG to enemies within the area of effect. The Resonator with this Echo equipped in the main slot gains 12.00% Fusion DMG Bonus and 12.00% Basic Attack DMG Bonus. \r\n\r\nCD: 25s.'),
(12, 'Bell-Borne Geochelone', 4, 'Moonlit Clouds, Rejuvenating Glow', 'Bell-Borne Geochelone.jpg', 'Activate the protection of Bell-Borne Geochelone. Deal Glacio DMG based on 145.92% of the current character\'s DEF to nearby enemies, and obtain a Bell-Borne Shield that lasts for 15s The Bell-Borne Shield provides 50.00% DMG Reduction and 10.00% DMG Boost for the current team members, and disappears after the current character is hit for 3 times. \r\n\r\nCD: 20s'),
(13, 'Nightmare: Lampylumen Myriad', 4, 'Frosty Resolve, Empyrean Anthem', 'Nightmare_Lampylumen_Myriad.jpg', 'Summon Nightmare: Lampylumen Myriad and attack surrounding enemies, dealing 273.60% Glacio DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Glacio DMG Bonus and deals 30.00% more Coordinated Attack DMG. \r\n\r\nCD: 20s.'),
(14, 'Mech Abomination', 4, 'Lingering Tunes', 'Mech_Abomination.jpg', 'Strike enemies in front, dealing 48.64% Electro DMG, and summon Mech Waste to attack. Mech Waste deals 320.00% Electro DMG on hit and explodes after a while, dealing 160.00% Electro DMG. After casting this Echo Skill, increase the current character\'s ATK by 12.00% for 15s. Damage dealt by Mech Waste equals to the Resonator\'s Outro Skill DMG. \r\n\r\nCD: 20s'),
(15, 'Hyvatia', 4, 'Pact of Neonlight Leap, Rite of Gilded Revelation', 'Hyvatia.jpg', 'Summon Hyvatia to fire lasers at enemies from mid-air, dealing 27.36% Spectro DMG 10 times. Casting Outro Skill within 15s after summoning Hyvatia grants 10.00% All-Attribute DMG Bonus to the next Resonator using Intro Skill for 15s. \r\n\r\nCD: 20s.'),
(16, 'Reactor Husk', 4, 'Halo of Starry Radiance, Chromatic Foam', 'Reactor_Husk.jpg', 'Transform into a Reactor Husk, jumping into the air and unleashing a heavy slash that deals 351.00% Fusion DMG to enemies. The Resonator with this Echo equipped in their main slot gain 10.00% Energy Regen. \r\n\r\nCD: 20s.'),
(17, 'Tempest Mephis', 4, 'Void Thunder', 'Tempest_Mephis.jpg', 'Transform into Tempest Mephis to perform tail swing attacks followed by a claw attack. The lightning strike summoned by the tail swing deals 102.48% Electro DMG each time, while the claw attack deals 175.68% Electro DMG. After the claw hit, increase the current character\'s Electro DMG by 12.00% and Heavy Attack DMG by 12.00% for 15s. \r\n\r\nCD: 20s'),
(18, 'Nightmare: Tempest Mephis', 4, 'Void Thunder, Empyrean Anthem', 'Nightmare_Tempest_Mephis.jpg', 'Transform into Nightmare: Tempest Mephis and attack surrounding enemies, dealing 405.00% Electro DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Electro DMG Bonus and 12.00% Resonance Skill DMG Bonus. \r\n\r\nCD: 25s.'),
(19, 'Nightmare: Thundering Mephis', 4, 'Void Thunder', 'Nightmare_Thundering_Mephis.jpg', 'Transform into Nightmare: Thundering Mephis and attack enemies in front, dealing 405.00% Electro DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Electro DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 25s.'),
(25, 'Lioness of Glory', 4, 'Flaming Clawprint', 'Lioness_of_Glory.jpg', 'Summon the Halberd of Glory to crush an area, dealing 82.08% Fusion DMG to nearby targets, and then blast off after a short delay, dealing 191.52% Fusion DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Fusion DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 20s'),
(26, 'Nightmare: Kelpie', 4, 'Gusts of Welkin, Windward Pilgrimage', 'Nightmare_Kelpie.jpg', 'Transform into Nightmare: Kelpie to attack nearby targets, dealing 405.00% Glacio DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Glacio DMG Bonus and 12.00% Aero DMG Bonus. Switching out the Resonator with Outro Skill summons Nightmare: Kelpie to deal 405.00% Aero DMG. \r\n\r\nCD: 25s'),
(28, 'Lady of the Sea', 4, 'Crown of Valor', 'Lady_of_the_Sea.jpg', 'Summon a Tidestorm to deal 13.68% Aero DMG ten times and 164.16% Aero DMG one time to enemies. The Resonator with this Echo equipped in the main slot gains 12.00% Aero DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 20s'),
(29, 'Nameless Explorer', 4, 'Sound of True Name, Reel of Spliced Memories', 'Nameless_Explorer.jpg', 'Summon Nameless Explorer to attack enemies along its path, dealing 273.60% Aero DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Aero DMG Bonus and 20.00% Echo Skill DMG Bonus. \r\n\r\nCD: 20s.'),
(30, 'Hecate', 4, 'Empyrean Anthem', 'Hecate.jpg', 'Summon 3 twirling Crescent Servants around you. Crescent Servants attack enemies with their spinning blades, dealing 45.59% Havoc DMG. Triggering a Counterattack with the Echo attacks resets the Crescent Servants\' duration. The Resonator with this Echo equipped in the main slot has their Coordinated Attack DMG increased by 40.00%. \r\n\r\nCD: 20s.'),
(31, 'Nightmare: Hecate', 4, 'Dream of the Lost', 'Nightmare_Hecate.jpg', 'Transform into Nightmare: Hecate. Leap up and smash down, dealing 3 stages of damage, each dealing Havoc DMG equal to 152.39% of her ATK. The Resonator with the Echo equipped in the main slot gains 12.00% Havoc DMG Bonus and 20.00% Echo Skill DMG Bonus. \r\n\r\nCD: 25s'),
(33, 'Reminiscence: Fenrico', 4, 'Dream of the Lost, Law of Harmony', 'Reminiscence_Fenrico.jpg', 'Summon the Talons of Decree to attack nearby enemies, dealing 273.60% Aero DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Aero DMG Bonus and 12.00% Heavy Attack DMG Bonus. \r\n\r\nCD: 20s.'),
(34, 'Jué', 4, 'Celestial Light', 'Jue.jpg', 'Summon Jué to the aid. Jué soars through the air, dealing 48.64% Spectro DMG, and summons thunderbolts that strike nearby enemies up to 5 times, each hit dealing 19.46% Spectro DMG. Jué then spirals downward, attacking surrounding enemies twice, each hit dealing 48.64% Spectro DMG. Casting this Echo Skill grants the Resonator a Blessing of Time effect that lasts 15s, during when: - The Resonator gains 16.00% Resonance Skill DMG Bonus. - When the Resonator\'s Resonance Skill hits the target, inflict 16.00% Spectro DMG 1 time per second for 15s, considered as the Resonator\'s Resonance Skill DMG. \r\n\r\nCD: 20s'),
(35, 'Reminiscence: Fleurdelys', 4, 'Gusts of Welkin, Windward Pilgrimage', 'Reminiscence_Fleurdelys.jpg', 'Summon Windcleaver and attack the target, dealing 27.36% Aero DMG 8 times and 136.80% Aero DMG once. The Resonator with this Echo equipped in the main slot gains 10.00% Aero DMG Bonus. When Resonator: Aero or Cartethyia equips this Echo, they gain 10.00% more Aero DMG Bonus. \r\n\r\nCD: 20s.'),
(36, 'Reminiscence: Threnodian - Leviathan', 4, 'Flamewing\'s Shadow, Thread of Severed Fate', 'Reminiscence_Threnodian_-_Leviathan.jpg', 'Summon a Collapsing Horizon, dealing two instances of 131.04% Havoc DMG to the nearby enemies and obtaining the Core of Collapse for 15s. While it lasts, Core of Collapse deals 24.57% Havoc DMG when the active Resonator in the team deals damage. This effect can be triggered once every 0.5s, up to 8 {Cus:Sap,S=time P=times SapTag=3}. Enemies with Havoc Bane take 100% more DMG from this effect. The Resonator with this Echo equipped in the main slot gains 12.00% Havoc DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 25s'),
(37, 'Sigillum', 4, 'Trailblazing Star', 'Sigillum.jpg', 'Summon Sigillum to unleash two attacks, dealing 68.40% and 205.20% Fusion DMG respectively. When equipped in the main slot by Aemeath, it grants 25.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 20s'),
(38, 'Abyssal Gladius', 3, 'Tidebreaking Courage, Midnight Veil, Thread of Severed Fate', 'Abyssal_Gladius.jpg', 'Transform into Abyssal Gladius and attack enemies in front of you with the sword, dealing 268.20% Glacio DMG. Hold the Echo Skill to maintain the Echo form for a while to slash enemies and cast a ranged attack forward, dealing 268.20% and 670.50% Glacio DMG respectively. \r\n\r\nCD: 15s.'),
(39, 'Abyssal Mercator', 3, 'Frosty Resolve, Eternal Radiance', 'Abyssal_Mercator.jpg', 'Transform into Abyssal Mercator and summon 3 Ice Spikes to attack enemies, each dealing 89.39% Glacio DMG. \r\n\r\nCD: 15s.'),
(40, 'Abyssal Patricius', 3, 'Empyrean Anthem, Frosty Resolve', 'Abyssal_Patricius.jpg', 'Transform into Abyssal Patricius and charge forward to attack enemies, dealing 268.20% Glacio DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Glacio DMG Bonus. \r\n\r\nCD: 15s.'),
(41, 'Autopuppet Scout', 3, 'Celestial Light, Freezing Frost', 'Autopuppet_Scout.jpg', 'Transform into Autopuppet Scout, dealing 272.00% Glacio DMG to the surroundings, and generate up to 3 Ice Walls to block off the enemies. \r\n\r\nCD: 15s'),
(43, 'Carapace', 3, 'Moonlit Clouds, Sierra Gale', 'Carapace.jpg', 'Transform into Carapace to perform a spinning attack that deals 112.00% Aero DMG, followed by a slash that deals 168.00% Aero DMG. \r\n\r\nCD: 15s'),
(44, 'Chasm Guardian', 3, 'Lingering Tunes, Rejuvenating Glow', 'Chasm_Guardian.jpg', 'Transform into Chasm Guardian to perform a Leap Strike that deals 273.60% Havoc DMG on hit. Current character loses 10.00% HP after the hit lands. Periodically restore current character\'s HP after 5s for up to 10.00% of their Max HP. \r\n\r\nCD: 15s'),
(46, 'Corrosaurus', 3, 'Flaming Clawprint, Flamewing\'s Shadow', 'Corrosaurus.jpg', 'Summon a Corrosaurus to attack enemies, dealing 273.60% Fusion DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Fusion DMG Bonus and 20.00% Echo Skill DMG Bonus. \r\n\r\nCD: 20s'),
(48, 'Cyan-Feathered Heron', 3, 'Sierra Gale, Celestial Light', 'Cyan-Feathered_Heron.jpg', 'Transform into Cyan-Feathered Heron and charge at the enemies, dealing 236.80% Aero DMG; This Echo Skill interrupts enemy Special Skills upon dealing damage. \r\n\r\nCD: 15s'),
(49, 'Diurnus Knight', 3, 'Eternal Radiancem, Tidebreaking Courage', 'Diurnus_Knight.jpg', 'Transform into Diurnus Knight and charge forward to attack enemies with the sword, dealing 268.20% Spectro DMG. DMG dealt to enemies inflicted by Spectro Frazzle is increased by 100.00%. \r\n\r\nCD: 15s.'),
(50, 'Flautist', 3, 'Lingering Tunes, Void Thunder', 'Flautist.jpg', 'Transform into Flautist, continuously emitting Electro lasers, dealing 53.28% Electro DMG for a total of 10 times. Gain 1 Concerto Energy every time a hit lands. \r\n\r\nCD: 15s'),
(51, 'Flora Reindeer', 3, 'Rite of Gilded Revelation, Reel of Spliced Memories', 'Flora_Reindeer.jpg', 'Summon a Flora Reindeer to attack enemies within a large range, dealing 192.60% Aero DMG. \r\n\r\nCD: 15s.'),
(52, 'Frostbite Coleoid', 3, 'Halo of Starry Radiance, Wishes of Quiet Snowfall', 'Frostbite_Coleoid.jpg', 'Summon a Frostbite Coleoid to punch enemies, dealing 192.60% Glacio DMG. \r\n\r\nCD: 15s.'),
(53, 'Glacio Dreadmane', 3, 'Moonlit Clouds, Freezing Frost', 'Glacio_Dreadmane.jpg', 'Lacerate enemies as a Glacio Dreadmane, dealing 214.40% Glacio DMG on each hit. Equipped with 2 charges and can be cast mid-air. Glacio Dreadmane deals 20.00% more DMG while in mid-air and generates 6 Icicles upon landing, each dealing 32.00% Glacio DMG. \r\n\r\nCD: 20s'),
(54, 'Glommoth', 3, 'Trailblazing Star', 'Glommoth.jpg', 'Summon a Glommoth to stomp enemies, dealing 273.60% Glacio DMG. Casting Outro Skill within 15s after summoning Glommoth grants 12.00% Glacio DMG Bonus to the incoming Resonator for 15s. \r\n\r\nCD: 20s.'),
(55, 'Havoc Dreadmane', 3, 'Molten Rift, Havoc Eclipse', 'Havoc_Dreadmane.jpg', 'Transform into a Havoc Dreadmane to perform up to 2 tail strikes. Each strike deals 116.64% Havoc DMG and inflicts an additional instance of 77.76% Havoc DMG upon hitting the target. \r\n\r\nCD: 15s'),
(56, 'Hoochief', 3, 'Rejuvenating Glow, Sierra Gale', 'Hoochief_Cyclone.jpg', 'Transform into Hoochief and smack the enemies, dealing 268.20% Aero DMG. \r\n\r\nCD: 15s'),
(57, 'Hurriclaw', 3, 'Tidebreaking Courage, Gusts of Welkin, Crown of Valor', 'Hurriclaw.jpg', 'Transform into Hurriclaw and charge forward, dealing 156.60% Aero DMG upon hit plus 156.60% Aero DMG with a sweep attack. Hold the Echo Skill to continue charging forward. Use Echo Skill again while charging to perform a sweep attack. \r\n\r\nCD: 20s.'),
(58, 'Ironhoof', 3, 'Pact of Neonlight Leap', 'Ironhoof.jpg', 'Transform into an Ironhoof to charge at enemies, dealing 53.64% Fusion DMG. At the end of the charge, unleash a goring attack that deals 13.41% Fusion DMG 3 times and 174.33% Fusion DMG once. \r\n\r\nCD: 15s.'),
(60, 'Kronablight', 3, 'Trailblazing Star, Chromatic Foam', 'Kronablight.jpg', 'Transform into a Kronablight, soar into the air, and dive to deal 268.20% Electro DMG to the enemies. \r\n\r\nCD: 15s'),
(63, 'Mining Reindeer', 3, 'Pact of Neonlight Leap', 'Mining_Reindeer.jpg', 'Summon a Mining Reindeer to launch a charged attack at enemies, dealing 237.60% Electro DMG. \r\n\r\nCD: 20s.'),
(64, 'Nightmare: Cyan-Feathered Heron', 3, 'Law of Harmony', 'Nightmare_Cyan-Feathered_Heron.jpg', 'Transform into Cyan-Feathered Heron and charge at the enemies, dealing 236.80% Aero DMG; This Echo Skill interrupts enemy Special Skills upon dealing damage. \r\n\r\nCD: 15s'),
(65, 'Nightmare: Roseshroom', 3, 'Thread of Severed Fate', 'Nightmare_Roseshroom.jpg', 'Summon a Roseshroom that fires a laser, dealing 57.07% Havoc DMG up to 3 times. \r\n\r\nCD: 15s'),
(66, 'Nightmare: Tambourinist', 3, 'Dream of the Lost', 'Nightmare_Tambourinist.jpg', 'Summon a Tambourinist that plays out Melodies of Annihilation. Any Resonator on the team gains the following effect for 10s upon obtaining a Melody of Annihilation: When the Resonator hits a target, the Tambourinist deals 14.40% Havoc DMG to the target, up to 10 times. \r\n\r\nCD: 15s'),
(67, 'Nightmare: Violet-Feathered Heron', 3, 'Crown of Valor', 'Nightmare_Violet-Feathered_Heron.jpg', 'Transform into Violet-Feathered Heron and enter a Parry Stance. Counterattack when the Parry stance is over, dealing 288.00% Electro DMG. If attacked during Parry Stance, you can counterattack in advance and additionally recover 5 Concerto Energy. \r\n\r\nCD: 15s'),
(68, 'Nightmare: Viridblaze Saurian', 3, 'Flamewing\'s Shadow', 'Nightmare_Viridblaze_Saurian.jpg', 'Summon a Viridblaze Saurian to continuously spit fire, dealing 17.12% Fusion DMG 10 times. \r\n\r\nCD: 15s'),
(69, 'Nocturnus Knight', 3, 'Midnight Veil, Empyrean Anthem', 'Nocturnus_Knight.jpg', 'Transform into Nocturnus Knight and strike enemies in front of you from the air, dealing 268.20% Havoc DMG. \r\n\r\nCD: 15s.'),
(70, 'Pilgrim\'s Shell', 3, 'Windward Pilgrimage, Flaming Clawprint', 'Pilgrim_s_Shell.jpg', 'Transform into a Pilgrim\'s Shell to attack nearby enemies, dealing 268.20% Aero DMG. \r\n\r\nCD: 15s'),
(72, 'Rage Against the Statue', 3, 'Eternal Radiance, Gusts of Welkin, Law of Harmony', 'Rage_Against_the_Statue.jpg', 'Transform into Rage Against the Statue to attack enemies, dealing 313.20% Spectro DMG. Hold the Echo Skill to maintain the Echo form and charge towards enemies, dealing 469.80% Spectro DMG. \r\n\r\nCD: 20s.'),
(73, 'Reminiscence - Kronaclaw', 3, 'Trailblazing Star, Chromatic Foam', 'Reminiscence_Kronaclaw.jpg', 'Transform into a Kronaclaw and soar into the air to deal 8.04% Aero DMG up to 8 times and 24.13% Aero DMG 2 times, then dive to deal 155.55% Aero DMG 1 time. \r\n\r\nCD: 15s'),
(74, 'Rocksteady Guardian', 3, 'Rejuvenating Glow, Celestial Light', 'Rocksteady_Guardian.jpg', 'Transform into Rocksteady Guardian and enter a Parry State. Upon being attacked, deal Spectro DMG equal to 8.29% of the Resonator\'s Max HP, and perform a follow-up attack that deals Spectro DMG equal to 8.29% of the Resonator\'s Max HP. Use the Echo Skill again to exit the transformation. If the attack received is a Special Skill attack, interrupt the enemy\'s Special Skill, gain a Shield equal to 30% Max HP, and perform a two-stage follow-up attack, each dealing Spectro DMG equal to 5.52% of the Resonator\'s Max HP. These follow-up attacks simultaneously launch three ground-breaking waves, each dealing Spectro DMG equal to 4.59% of the Resonator\'s Max HP. \r\n\r\nCD: 15s'),
(75, 'Roseshroom', 3, 'Freezing Frost, Havoc Eclipse', 'Roseshroom.jpg', 'Summon a Roseshroom that fires a laser, dealing 57.07% Havoc DMG up to 3 times. \r\n\r\nCD: 15s'),
(76, 'Sabercat Prowler', 3, 'Pact of Neonlight Leap, Pact of Neonlight Leap, Sound of True Name', 'Sabercat_Prowler.jpg', 'Summon a Sabercat Prowler to fire beams at enemies, dealing 192.60% Havoc DMG. \r\n\r\nCD: 15s.'),
(77, 'Sabercat Reaver', 3, 'Pact of Neonlight Leap, Halo of Starry Radiance, Sound of True Name', 'Sabercat_Reaver.jpg', 'Summon a Sabercat Reaver to attack enemies, dealing 192.60% Fusion DMG. \r\n\r\nCD: 15s.'),
(78, 'Spacetrek Explorer', 3, 'Halo of Starry Radiance, Chromatic Foam, Sound of True Name', 'Spacetrek_Explorer.jpg', 'Summon a Spacetrek Explorer to grant nearby active Resonators in the team a Shield equal to 10% of the summoner\'s Max HP for 4s. \r\n\r\nCD: 20s'),
(79, 'Spearback', 3, 'Lingering Tunes, Moonlit Clouds', 'Spearback.jpg', 'Summon a Spearback to perform 5 consecutive attacks. The first 4 attacks deal 29.96% Physical DMG, and the last deals 51.36% Physical DMG. \r\n\r\nCD: 15s'),
(80, 'Stonewall Bracer', 3, 'Rejuvenating Glow, Moonlit Clouds', 'Stonewall_Bracer.jpg', 'Transform into Stonewall Bracer and charge forward, dealing 112.64% Physical DMG on-hit, then smash to deal 168.96% Physical DMG, and gain a shield of 10.00% of current character\'s Max HP that lasts 7s. Use the Echo skill again to exit the transformation state. \r\n\r\nCD: 15s'),
(81, 'Tambourinist', 3, 'Freezing Frost, Havoc Eclipse', 'Tambourinist.jpg', 'Summon a Tambourinist that plays out Melodies of Annihilation. Any Resonator on the team gains the following effect for 10s upon obtaining a Melody of Annihilation: When the Resonator hits a target, the Tambourinist deals 14.40% Havoc DMG to the target, up to 10 times. \r\n\r\nCD: 15s'),
(82, 'Twin Nova - Collapsar Blade', 3, 'Rite of Gilded Revelation, Trailblazing Star, Sound of True Name', 'Twin_Nova_Collapsar_Blade.jpg', 'Transform into a Twin Nova: Collapsar Blade to rapidly fire at enemies for 5s, with each attack dealing 2.01% Electro DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Electro DMG Bonus and 12.00% Basic Attack DMG Bonus. \r\n\r\nCD: 8s. \r\n\r\nIf Twin Nova: Nebulous Cannon is equipped in another slot on the Resonator: - Casting Echo Skill in succession transforms you into Collapsar Blade and Nebulous Cannon alternately and is considered casting Echo skills of the same name. - DMG dealt by Twin Nova: Collapsar Blade becomes Spectro DMG. The Electro DMG Bonus gained from equipping it in the main slot is turned into Spectro DMG Bonus. - Casting Basic Attacks grants 1 {Cus:Sap,S=stack P=stacks SapTag=1} of Dyad Origins. Casting Resonance Skill grants 3 {Cus:Sap,S=stack P=stacks SapTag=2} of Dyad Origins. Dyad Origins can stack up to 6 times and lasts for 8s. Each stack increases Echo Skill DMG by 10%, and all stacks are cleared after this Echo Skill ends. - This skill is capped at 2 uses. Initially, this skill can be used 2 times, with 1 use added every 8s.'),
(83, 'Twin Nova - Nebulous Cannon', 3, 'Rite of Gilded Revelation, Chromatic Foam', 'Twin_Nova_Nebulous_Cannon.jpg', 'Transform into a Twin Nova: Nebulous Cannon to slash enemies twice, with each attack dealing 80.51% Spectro DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Spectro DMG Bonus and 12.00% Basic Attack DMG Bonus. \r\n\r\nCD: 8s. \r\n\r\nIf Twin Nova: Collapsar Blade is equipped in another slot on the Resonator: - Casting Echo Skill in succession transforms you into Nebulous Cannon and Collapsar Blade alternately and is considered casting Echo skills of the same name. The DMG Bonus from the Echo in the main slot remains unchanged. - DMG dealt by Twin Nova: Collapsar Blade becomes Spectro DMG. - Casting Basic Attacks grants 1 {Cus:Sap,S=stack P=stacks SapTag=1} of Dyad Origins. Casting Resonance Skill grants 3 {Cus:Sap,S=stack P=stacks SapTag=2} of Dyad Origins. Dyad Origins can stack up to 6 times and lasts for 8s. Each stack increases Echo Skill DMG by 10%, and all stacks are cleared after this Echo Skill ends. -This skill is capped at 2 uses. Initially, this skill can be used 2 times, with 1 use added every 8s.'),
(84, 'Violet-Feathered Heron', 3, 'Molten Rift, Void Thunder', 'Violet-Feathered_Heron.jpg', 'Transform into Violet-Feathered Heron and enter a Parry Stance. Counterattack when the Parry stance is over, dealing 288.00% Electro DMG. If attacked during Parry Stance, you can counterattack in advance and additionally recover 5 Concerto Energy. \r\n\r\nCD: 15s'),
(85, 'Viridblaze Saurian', 3, 'Moonlit Clouds, Molten Rift', 'Viridblaze_Saurian.jpg', 'Summon a Viridblaze Saurian to continuously spit fire, dealing 17.12% Fusion DMG 10 times. \r\n\r\nCD: 15s'),
(86, 'Vitreum Dancer', 3, 'Empyrean Anthem, Eternal Radiance', 'Vitreum_Dancer.jpg', 'Transform into Vitreum Dancer and attack surrounding enemies, dealing 313.20% Electro DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Electro DMG Bonus. \r\n\r\nCD: 20s.'),
(87, 'Windlash Coleoid', 3, 'Rite of Gilded Revelation', 'Windlash_Coleoid.jpg', 'Transform into a Windlash Coleoid to kick enemies, dealing 268.20% Aero DMG. \r\n\r\nCD: 15s.'),
(88, 'Aero Drake', 1, 'Gusts of Welkin, Tidebreaking Courage, \r\nFlaming Clawprint', 'Aero_Drake.jpg', 'Summon an Aero Drake to attack enemies, dealing 129.60% Aero DMG. \r\n\r\nCD: 8s.'),
(89, 'Aero Predator', 1, 'Void Thunder, Sierra Gale', 'Aero_Predator.jpg', 'Summon an Aero Predator that throws a dart forward. The dart will bounce between enemies up to three times, dealing 28.80% Aero DMG each time it hits. \r\n\r\nCD: 8s'),
(90, 'Aero Prism', 1, 'Eternal Radiance, Tidebreaking Courage', 'Aero_Prism.jpg', 'Summon an Aero Prism to attack enemies, dealing 19.26% Aero DMG. \r\n\r\nCD: 15s.'),
(91, 'Baby Viridblaze Saurian', 1, 'Lingering Tunes, Void Thunder, Molten Rift\r\n', 'Baby_Viridblaze_Saurian.jpg', 'Transform into Baby Viridblaze Saurian to rest in place, and slowly restore HP. \r\n\r\nCD: 8s'),
(92, 'Calcified Junrock', 1, 'Tidebreaking Courage, Empyrean Anthem, \r\nCrown of Valor', 'Calcified_Junrock.jpg', 'Summon a Calcified Junrock that restores HP for nearby Resonators in the team by 2.52% of their Max HP, up to 5 times. \r\n\r\nCD: 15s'),
(93, 'Chest Mimic', 1, 'Midnight Veil, Empyrean Anthem, Frosty Resolve', 'Chest_Mimic.jpg', 'Summon a Chest Mimic to attack enemies with 3 consecutive strikes, each dealing 64.19% Spectro DMG. \r\n\r\nCD: 15s.'),
(94, 'Chirpuff', 1, 'Havoc Eclipse, Sierra Gale', 'Chirpuff.jpg', 'Summon a Chirpuff that self-inflates and blasts a powerful gust of wind forward 3 times. Each blast inflicts 38.40% Aero DMG and pushes enemies backwards. \r\n\r\nCD: 8s'),
(95, 'Chop Chop: Headless', 1, 'Eternal Radiance, Tidebreaking Courage', 'Chop_Chop_Headless.jpg', 'Summon a Chop Chop: Headless to attack enemies, dealing 129.60% Fusion DMG. \r\n\r\nCD: 8s.'),
(96, 'Chop Chop: Leftless', 1, 'Frosty Resolve, Tidebreaking Courage', 'Chop_Chop_Leftless.jpg', 'Summon a Chop Chop: Leftless to attack enemies, dealing 129.60% Spectro DMG. \r\n\r\nCD: 8s.'),
(97, 'Chop Chop: Rightless', 1, 'Tidebreaking Courage, Frosty Resolve', 'Chop_Chop_Rightless.jpg', 'Summon a Chop Chop: Rightless to attack enemies, dealing 129.60% Havoc DMG. \r\n\r\nCD: 8s.'),
(98, 'Clang Bang', 1, 'Celestial Light, Freezing Frost', 'Clang_Bang.jpg', 'Summon a Clang Bang that follows the enemy and eventually self-combusts, dealing 32.00%+64 Glacio DMG. \r\n\r\nCD: 8s'),
(99, 'Cruisewing', 1, 'Rejuvenating Glow, Moonlit Clouds, Celestial Light', 'Cruisewing.jpg', 'Summon a Cruisewing that restores HP for all current team characters by 1.80% of their Max HPs plus an additional 80 points of HP, up to 4 times. \r\n\r\nCD: 8s'),
(100, 'Devotee\'s Flesh', 1, 'Gusts of Welkin, Windward Pilgrimage, Flaming Clawprint', 'Devotee_Flesh.jpg', 'Summon a Devotee\'s Flesh to attack enemies, dealing 43.20% Aero DMG 3 times. \r\n\r\nCD: 8s'),
(101, 'Diamondclaw', 1, 'Moonlit Clouds, Lingering Tunes', 'Diamondclaw.jpg', 'Transform into Crystal Scorpion and enter a Parry State. Counterattack when the Parry State is over, dealing 48.00%+96 Physical DMG. \r\n\r\nCD: 8s'),
(102, 'Diggy Duggy', 1, 'Eternal Radiance, Tidebreaking Courage', 'Diggy_Duggy.jpg', 'Transform into Diggy Duggy and jump up into the air to smash onto enemies, dealing 268.20% Physical DMG. \r\n\r\nCD: 15s.'),
(103, 'Dwarf Cassowary', 1, 'Sierra Gale, Rejuvenating Glow', 'Dwarf_Cassowary.jpg', 'Summon a Dwarf Cassowary that tracks and attacks the enemy, dealing 38.40% Physical DMG 3 time(s). \r\n\r\nCD: 8s'),
(104, 'Electro Drake', 1, 'Gusts of Welkin, Midnight Veil, Flaming Clawprint', 'Electro_Drake.jpg', 'Summon an Electro Drake to attack enemies, dealing 43.20% Electro DMG 3 times. \r\n\r\nCD: 8s.'),
(105, 'Electro Predator', 1, 'Molten Rift, Void Thunder', 'Electro_Predator.jpg', 'Summon an Electro Predator to shoot the enemy 5 times. The first 4 shots deals 17.28% Electro DMG, and the last deals 46.08% Electro DMG. \r\n\r\nCD: 8s'),
(106, 'Excarat', 1, 'Freezing Frost, Havoc Eclipse', 'Excarat.jpg', 'Transform into an Excarat and tunnel underground to advance. In this state, you have the ability to change your direction and are immune to damage. \r\n\r\nCD: 8s'),
(107, 'Fae Ignis', 1, 'Midnight Veil, Eternal Radiance, Dream of the Lost', 'Fae_Ignis.jpg', 'Summon a Fae Ignis to attack enemies, dealing 129.60% Havoc DMG. \r\n\r\nCD: 8s.'),
(108, 'Fission Junrock', 1, 'Moonlit Clouds, Void Thunder, Rejuvenating Glow', 'Fission_Junrock.jpg', 'Summon a Fission Junrock. Generate a Resonance Effect that restores 2% HP for friendly units each time. If not in combat, you can pick up minerals or plants nearby. \r\n\r\nCD: 15s'),
(109, 'Flora Drone', 1, 'Pact of Neonlight Leap, Rite of Gilded Revelation, Sound of True Name', 'Flora_Drone.jpg', 'Summon a Flora Drone, dealing 64.80% Aero DMG to enemies and healing Resonators within range by 3.60% of their Max HP plus an additional 160 HP. \r\n\r\nCD: 8s'),
(110, 'Frostscourge Stalker', 1, 'Midnight Veil, Eternal Radiance', 'Frostscourge_Stalker.jpg', 'Summon a Frostscourge Stalker to attack enemies, dealing 129.60% Glacio DMG. \r\n\r\nCD: 8s.'),
(111, 'Fusion Drake', 1, 'Flaming Clawprint, Windward Pilgrimage', 'Fusion_Drake.jpg', 'Summon a Fusion Drake to attack enemies, dealing 25.92% Fusion DMG 3 times. \r\n\r\nCD: 8s'),
(112, 'Fusion Dreadmane', 1, 'Rejuvenating Glow, Molten Rift', 'Fusion_Dreadmane.jpg', 'Summon a Fusion Dreadmane that fiercely strikes the enemy, dealing 32.00%+64 Fusion DMG. \r\n\r\nCD: 8s'),
(113, 'Fusion Prism', 1, 'Freezing Frost, Lingering Tunes, Molten Rift', 'Fusion_Prism.jpg', 'Summon a Fusion Prism to fire a crystal shard, dealing 32.00%+64 Fusion DMG. \r\n\r\nCD: 8s'),
(114, 'Fusion Warrior', 1, 'Sierra Gale, Void Thunder, Molten Rift', 'Fusion_Warrior.jpg', 'Transform into Fusion Warrior to perform a Counterattack. If the Counterattack is successful, the cooldown time of this skill will be reduced by 70.00%, and 288.00% Fusion DMG will be dealt. \r\n\r\nCD: 15s'),
(115, 'Geospider S4', 1, 'Pact of Neonlight Leap, Halo of Starry Radiance, Trailblazing Star', 'Geospider_S4.jpg', 'Summon a Geospider S4 to attack enemies, dealing 51.84% Spectro DMG once and 77.76% Spectro DMG once. \r\n\r\nCD: 8s.'),
(116, 'Galescourge Stalker', 1, 'Frosty Resolve, Empyrean Anthem', 'Galescourge_Stalker.jpg', 'Summon a Galescourge Stalker that restores nearby party members\' HP by 2.70% of their Max HP, up to 3 times. \r\n\r\nCD: 8s.'),
(117, 'Glacio Drake', 1, 'Gusts of Welkin, Windward Pilgrimage', 'Glacio_Drake.jpg', 'Summon a Glacio Drake to attack enemies, dealing 25.92% Glacio DMG 5 times. \r\n\r\nCD: 8s.'),
(118, 'Glacio Predator', 1, 'Celestial Light, Freezing Frost', 'Glacio_Predator.jpg', 'Summon a Glacio Predator that throws an ice spear, dealing 46.08% Glacio DMG on hit. Deal 4.61% Glacio DMG up to 10 times during the charging time, and 23.04% Glacio DMG when the spear explodes. \r\n\r\nCD: 8s'),
(119, 'Golden Junrock', 1, 'Eternal Radiance, Frosty Resolve, Law of Harmony', 'Golden_Junrock.jpg', 'Summon a Golden Junrock that charges forward, dealing 129.60% Spectro DMG to enemies in its path. \r\n\r\nCD: 8s'),
(120, 'Glacio Prism', 1, 'Havoc Eclipse, Moonlit Clouds, Freezing Frost', 'Glacio_Prism.jpg', 'Summon a Glacio Prism that continuously fires three crystal shards, each dealing 38.40% Glacio DMG. \r\n\r\nCD: 8s'),
(121, 'Gulpuff', 1, 'Celestial Light, Freezing Frost', 'Gulpuff.jpg', 'Summon a Gulpuff that blows bubbles 5 times, each time dealing 23.04% Glacio DMG. \r\n\r\nCD: 8s'),
(122, 'Havoc Drake', 1, 'Flaming Clawprint, Windward Pilgrimage, Thread of Severed Fate', 'Havoc_Drake.jpg', 'Summon a Havoc Drake to attack enemies, dealing 129.60% Havoc DMG 3 times. \r\n\r\nCD: 8s'),
(123, 'Havoc Prism', 1, 'Void Thunder, Celestial Light, Havoc Eclipse', 'Havoc_Prism.jpg', 'Summon a Havoc Prism to fire five crystal shards, each dealing 23.04% Havoc DMG. \r\n\r\nCD: 8s'),
(124, 'Havoc Warrior', 1, 'Celestial Light, Havoc Eclipse', 'Havoc_Warrior.jpg', 'Transform into Havoc Warrior to attack up to 3 times, dealing 171.73% Havoc DMG each time. \r\n\r\nCD: 15s'),
(125, 'Hoartoise', 1, 'Celestial Light, Freezing Frost', 'Hoartoise.jpg', 'Transform into Hoartoise and slowly restore HP. Use the Echo skill again to exit the transformation state. \r\n\r\nCD: 8s'),
(126, 'Hocus Pocus', 1, 'Frosty Resolve, Empyrean Anthem', 'Hocus_Pocus.jpg', 'Summon a Hocus Pocus to attack enemies with 3 consecutive strikes, each dealing 43.20% Havoc DMG. \r\n\r\nCD: 8s.'),
(127, 'Hooscamp', 1, 'Lingering Tunes, Sierra Gale', 'Hooscamp.jpg', 'Transform into Hooscamp Flinger and pounce at the enemies, dealing 48.00%+96 Aero DMG. \r\n\r\nCD: 8s'),
(128, 'Iceglint Dancer', 1, 'Trailblazing Star', 'Iceglint_Dancer.jpg', 'Transform into an Iceglint Dancer to attack enemies, dealing 205.20% Glacio DMG. \r\n\r\nCD: 8s.'),
(129, 'La Guardia', 1, 'Gusts of Welkin, Midnight Veil, Flaming Clawprint', 'La_Guardia.jpg', 'Transform into La Guardia and attack nearby targets, dealing 268.20% Physical DMG. Hold the Echo Skill to maintain the Echo form for a while to slash enemies and cast a ranged attack forward. The slash deals 268.20% Physical DMG, and the ranged attack deals 17.87% Physical DMG up to 15 times. \r\n\r\nCD: 15s.'),
(130, 'Lava Larva', 1, 'Lingering Tunes, Molten Rift', 'Lava_Larva.jpg', 'Summon a Lava Larva that continuously attacks enemies, dealing 38.40% Fusion DMG with each hit. The Lava Larva disappears when the summoner is switched out or moves too far away. \r\n\r\nCD: 8s'),
(131, 'Lottie Lost', 1, 'Tidebreaking Courage, Frosty Resolve', 'Lottie_Lost.jpg', 'Summon a Lottie Lost to attack enemies, dealing 129.60% Spectro DMG. \r\n\r\nCD: 8s.'),
(132, 'Mining Drone', 1, 'Halo of Starry Radiance, Rite of Gilded Revelation, Sound of True Name', 'Mining_Drone.jpg', 'Transform into a Mining Drone to attack enemies, dealing 102.60% Havoc DMG twice. \r\n\r\nCD: 8s.'),
(143, 'Nimbus Wraith', 1, 'Empyrean Anthem, Midnight Veil, Flamewing\'s Shadow', 'Nimbus_Wraith.jpg', 'Summon a Nimbus Wraith that restores the active Resonator\'s HP by 2.70% of their Max HP, up to 4 times. \r\n\r\nCD: 15s.'),
(144, 'Sabyr Boar', 1, 'Moonlit Clouds, Sierra Gale, Freezing Frost', 'Sabyr_Boar.jpg', 'Summon a Sabyr Boar to headbutt the enemy into the air, dealing 32.00%+64 Physical DMG. \r\n\r\nCD: 8s'),
(145, 'Sacerdos', 1, 'Gusts of Welkin, Windward Pilgrimage', 'Sacerdos.jpg', 'Summon a Sacerdos to attack enemies, dealing 64.80% Aero DMG 2 times. \r\n\r\nCD: 8s.'),
(146, 'Sagittario', 1, 'Gusts of Welkin, Eternal Radiance, Flaming Clawprint', 'Sagittario.jpg', 'Transform into Sagittario to move a certain distance and perform a ranged attack, dealing 268.20% Spectro DMG. Getting attacked while moving in the Sagittario form triggers form triggers a damage avoiding enhanced Dodge Counter, dealing 268.20% Spectro DMG once and 53.64% Spectro DMG 5 times. \r\n\r\nCD: 15s.'),
(147, 'Shadow Stepper', 1, 'Trailblazing Star, Chromatic Foam', 'Shadow_Stepper.jpg', 'Summon a Shadow Stepper to attack enemies, dealing 129.60% Havoc DMG. \r\n\r\nCD: 8s.'),
(148, 'Snip Snap', 1, 'Lingering Tunes, Rejuvenating Glow, Molten Rift', 'Snip_Snap.jpg', 'Summon a Snip Snap that throws fireballs at the enemy, dealing 32.00%+64 Fusion DMG on-hit. \r\n\r\nCD: 8s\r\n\r\n'),
(149, 'Spectro Drake', 1, 'Flaming Clawprint, Windward Pilgrimage', 'Spectro_Drake.jpg', 'Summon a Spectro Drake to attack enemies, dealing 43.20% Spectro DMG 3 times. \r\n\r\nCD: 8s'),
(150, 'Spectro Prism', 1, 'Molten Rift, Void Thunder, Celestial Light', 'Spectro_Prism.jpg', 'Summon a Spectro Prism to emit a laser that hits the enemy up to 8 times, dealing 14.40% Spectro DMG each time. \r\n\r\nCD: 8s'),
(151, 'Tick Tack', 1, 'Lingering Tunes, Rejuvenating Glow, Havoc Eclipse', 'Tick_Tack.jpg', 'Summon a Tick Tack that charges and bites the enemy. The charge from Tick Tack will deal 68.48% Havoc DMG to the enemy, and the bite will deal 102.72% Havoc DMG to the enemy. Reduces enemy Vibration Strength by up to 5.00% during 5s. \r\n\r\nCD: 15s'),
(152, 'Traffic Illuminator', 1, 'Void Thunder, Sierra Gale, Molten Rift', 'Traffic_Illuminator.jpg', 'Summon a Traffic Illuminator, immobilizing enemies for up to 1s. The immobilization will be lifted once the enemy is hit. \r\n\r\nCD: 15s'),
(153, 'Tremor Warrior', 1, 'Halo of Starry Radiance, Chromatic Foam', 'Tremor_Warrior.jpg', 'Transform into a Tremor Warrior and viciously attack enemies in the front, dealing 205.20% Electro DMG. \r\n\r\nCD: 8s.'),
(154, 'Vanguard Junrock', 1, 'Rejuvenating Glow, Void Thunder, Lingering Tunes', 'Vanguard_Junrock.jpg', 'Summon a Vanguard Junrock that charges forward, dealing 32.00%+64 Physical DMG to enemies in its path. \r\n\r\nCD: 8s'),
(155, 'Voltscourge Stalker', 1, 'Empyrean Anthem, Midnight Veil', 'Voltscourge_Stalker.jpg', 'Summon a Voltscourge Stalker to perform 3 stages of attacks on enemies, each dealing 43.20% Electro DMG. \r\n\r\nCD: 8s.'),
(156, 'Whiff Whaff', 1, 'Rejuvenating Glow, Moonlit Clouds, Sierra Gale', 'Whiff_Whaff.jpg', 'Summon a Whiff Whaff that triggers an air explosion, dealing 51.36% Aero DMG and produce a Low-pressure Zone. The Low-pressure Zone continuously pulls enemies nearby towards the center for 2s, dealing 19.97% Aero DMG up to 6 times. \r\n\r\nCD: 15s'),
(157, 'Baby Roseshroom', 1, 'Sierra Gale, Havoc Eclipse', 'Baby_Roseshroom.jpg', 'Summon a Baby Roseshroom that fires a laser, dealing 32.00%+64 Havoc DMG. \r\n\r\nCD: 8s'),
(158, 'Zig Zag', 1, 'Moonlit Clouds, Lingering Tunes, Celestial Light', 'Zig_Zag.jpg', 'Summon a Zig Zag that detonates Spectro energy, dealing 48.00%+96 Spectro DMG and creating a Stagnation Zone that lasts 1.8s. \r\n\r\nCD: 15s'),
(159, 'Zip Zap', 1, 'Pact of Neonlight Leap, Rite of Gilded Revelation, Chromatic Foam, Sound of True Name', 'Zip_Zap.jpg', 'Summon a Zip Zap to launch spinning attacks at enemies, dealing 25.92% Electro DMG 5 times. \r\n\r\nCD: 8s.'),
(160, 'Dreamless', 4, 'Havoc Eclipse', 'dreamless.jpg', 'Transform into Dreamless and perform 6 consecutive strikes. The first 5 strikes deal 54.08% Havoc DMG each, and the last strike deal 270.40% Havoc DMG. The DMG of this Echo Skill is increased by 50.00% during the first 5s after Rover: Havoc casts Resonance Liberation: Deadening Abyss. \r\n\r\nCD: 20s'),
(161, 'Feilian Beringal', 4, 'Sierra Gale', 'feilian_beringal.jpg', 'Transform into Feilian Beringal to perform a powerful kick. If the kick lands on an enemy, immediately perform a follow-up strike. The kick deals 231.84% Aero DMG, and the follow-up strike deals 283.36% Aero DMG. After the follow-up strike hits, the current character\'s Aero DMG increases by 12.00%, and the Heavy Attack DMG increases by 12.00% for 15s \r\n\r\nCD: 20s'),
(162, 'Impermanence Heron', 3, 'Moonlit Clouds', 'impermanence_heron.jpg', 'Transform into Impermanence Heron to fly up and smack down, dealing 310.56% Havoc DMG. Long press to stay as Impermanence Heron and continuously spit flames, each attack dealing 55.73% Havoc DMG. Once the initial attack lands on any enemy, the current character regains 10 Resonance Energy. If the current character uses their Outro Skill within the next 15s, the next character\'s damage dealt will be boosted by 12% for 15s.\r\n\r\nCD: 20s\r\n\r\n'),
(163, 'Mourning Aix', 4, 'Celestial Light', 'mourning_aix.jpg', 'Transform into Mourning Aix and perform 2 consecutive claw attacks, each attack dealing 157.44% and 236.16% Spectro DMG respectively. After the transformation, increase current character\'s Spectro DMG by 12.00% and Resonance Liberation DMG by 12.00% for 15s.\r\n\r\nCD: 20s'),
(164, 'Crownless', 4, 'Havoc Eclipse', 'crownless.jpg', 'Transform into Crownless and perform up to 4 consecutive attacks. The first 2 attacks deal 134.08% Havoc DMG each, the 3rd attack deals 100.56% Havoc DMG 2 times, and the 4th attack deals 67.04% Havoc DMG 3 times. After the transformation, increase current character\'s Havoc DMG by 12.00% and Resonance Skill DMG by 12.00% for 15s. \r\n\r\nCD: 20s'),
(165, 'Thundering Mephis', 4, 'Void Thunder', 'thundering_mephis.jpg', 'Transform into Nightmare: Thundering Mephis and attack enemies in front, dealing 405.00% Electro DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Electro DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 25s.'),
(166, 'Inferno Rider', 4, 'Molten Rift', 'inferno_rider.jpg', 'Transform into the Inferno Rider to launch up to 3 consecutive slashes in a row, each slash dealing 242.40%, 282.80%, and 282.80% Fusion DMG respectively. After the final hit, increase the current Resonator\'s Fusion DMG by 12.00% and Basic Attack DMG by 12.00% for 15s. Long press the Echo Skill to transform into the Inferno Rider and enter Riding Mode. When exiting Riding Mode, deal 282.80% Fusion DMG to enemies in front. \r\n\r\nCD: 20s'),
(167, 'Nightmare: Inferno Rider', 4, 'Molten Rift', 'Nightmare_Inferno_Rider.jpg', 'Transform into Nightmare: Inferno Rider and jump to attack enemies in front, dealing 405.00% Fusion DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Fusion DMG Bonus and 12.00% Resonance Skill DMG Bonus. Hold Echo Skill to transform into Nightmare: Inferno Rider and enter Riding Mode. When exiting Riding Mode, deal 283.50% Fusion DMG to enemies in front. \r\n\r\nCD: 25s.\r\n\r\n'),
(168, 'Lorelei', 3, 'Midnight Veil', 'lorelei.jpg', 'Transform into Lorelei and attack surrounding enemies, dealing 405.00% Havoc DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Havoc DMG Bonus and 12.00% Basic Attack DMG Bonus. \r\n\r\nCD: 25s.\r\n\r\n'),
(169, 'Sentry Construct', 1, 'Frosty Resolve', 'sentry_construct.jpg', 'Transform into Sentry Construct and attack enemies in front, dealing 405.00% Glacio DMG. Each time the Resonator with this Echo casts Resonance Liberation, it charges the Strike Capacitor. Once Strike Capacitor is at max level, the Echo\r\nSkill cooldown will be reset. Use Echo Skill to transform into Sentry Construct and dive into enemies from the air, dealing 405.00% Glacio DMG and freezing the target. The Resonator with this Echo equipped in their main slot gains 12.00% Glacio DMG Bonus and 12.00% Resonance Skill DMG Bonus. \r\n\r\nCD: 25s.'),
(170, 'The False Sovereign', 4, 'Crown of Valor', 'the_false_sovereign.jpg', 'Transform into the False Sovereign and dash forward in a spinning strike, dealing 55.35% Electro DMG 4 times. The Resonator with this Echo equipped in the main slot gains 12.00% Electro DMG Bonus and 12.00% Heavy Attack DMG Bonus. Upon casting Intro Skill, the False Sovereign is also summoned to deal 405.00% Electro DMG. Start with 2 charges. Gain 1 charge every 8s, up to 2 charges. \r\n\r\nCD: 8s'),
(171, 'Fallacy of No Return', 4, 'Rejuvenating Glow', 'fallacy_of_no_return.jpg', 'Activate the Echo Skill to summon a fraction of the Fallacy of No Return\'s power and deal a blast to the surrounding area, inflicting Spectro DMG equal to 15.86% of max HP, after which the Resonator gains 10% bonus Energy Regen and all team members 10% bonus ATK for 20s. Hold Echo Skill to unleash a series of flurry assaults at the cost of STA, each dealing Spectro DMG equal to 1.58% of max HP; Release to end the assail in a powerful blow, dealing Spectro DMG equal to 19.82% of max HP. \r\n\r\nCD: 20s'),
(172, 'Capitaneus', 3, 'Gusts of Welkin, Eternal Radiance, Windward Pilgrimage', 'capitaneus.jpg', 'Summon a Capitaneus to jump up and smash enemies, dealing 118.80% Spectro DMG. This attack generates 4 extra Merciless Judgements, each dealing 59.40% Spectro DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Spectro DMG Bonus and 12.00% Heavy Attack DMG Bonus. \r\n\r\nCD: 20s.'),
(173, 'Chop Chop', 1, 'Tidebreaking Courage, Empyrean Anthem, Dream of the Lost', 'chop_chop.jpg', 'Summon a Chop Chop to perform a series of consecutive attacks. The first 6 strikes each deal 19.26% Fusion DMG and finishing strike deals 77.04% Fusion DMG. \r\n\r\nCD: 15s.'),
(174, 'Cuddle Wuddle', 1, 'Midnight Veil, Frosty Resolve', 'cuddle_wuddle.jpg', 'Transform into Cuddle Wuddle and attack enemies with 4 strikes dealing 46.98% Physical DMG and 1 strike dealing 125.28% Physical DMG. \r\n\r\nCD: 20s.'),
(175, 'Kerasaur', 3, 'Windward Pilgrimage, Flaming Clawprint, Flamewing\'s Shadow', 'kerasaur.jpg', 'Transform into Kerasaur to leap into the air and slam down, dealing 268.20% Aero DMG. Shortly after hitting the target, cast Echo Skill again to charge at the target, dealing 268.20% Aero DMG. The Resonator with this Echo equipped in the main slot gains 12.00% Aero DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 15s'),
(176, 'Lightcrusher', 3, 'Celestial Light', 'lightcrusher.jpg', 'Lunge forward as a Lightcrusher, dealing 135.36% Spectro DMG. Generate 6 Ablucence on hit. Each Ablucence explosion deals 15.04% Spectro DMG. Hold the Echo Skill to stay in the Lightcrusher form, which allows you to leap up and pounce forward in the air for a short distance. \r\n\r\nCD: 15s'),
(177, 'Lumiscale Construct', 1, 'Void Thunder, Freezing Frost', 'lumiscale_construct.jpg', 'Transform into a Lumiscale Construct and enter a Parry Stance. If you are not attacked during the Parry Stance, slash to deal 553.60% Glacio DMG when the stance finishes. If attacked, counterattack instantly, dealing 553.60%+276.80% Glacio DMG. When hit with a Special Skill attack while in the Parry Stance, break the Special Skill and counterattack, dealing 553.60%+276.80% Glacio DMG. \r\n\r\nCD: 15s'),
(178, 'Questless Knight', 3, 'Frosty Resolve, Midnight Veil', 'questless_knight.jpg', 'Transform into Questless Knight and smash the surrounding enemies, dealing 313.20% Electro DMG. \r\n\r\nCD: 20s.');
INSERT INTO `sonatas` (`id`, `name`, `tier1_req`, `tier1_desc`, `tier2_req`, `tier2_desc`) VALUES
(1, 'Rejuvenating Glow', '2-Pc', 'Healing Bonus + 10%.', '5-Pc', 'Increases the ATK of all party members by 15% for 30s upon healing allies.'),
(2, 'Void Thunder', '2-Pc', 'Electro DMG + 10%.', '5-Pc', 'Electro DMG + 15% after releasing Heavy Attack or Resonance Skill. This effect stacks up to 2 times, each stack lasts 15s.'),
(3, 'Lingering Tunes', '2-Pc', 'ATK +10%', '5-Pc', 'While on the field, ATK increases by 5% every 1.5s. This effect stacks up to 4 times. Outro Skill DMG + 60%.'),
(4, 'Moonlit Clouds', '2-Pc', 'Energy Regen + 10%.', '5-Pc', 'Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.'),
(5, 'Molten Rift', '2-Pc', 'Fusion DMG + 10%.', '5-Pc', 'Fusion DMG + 30% for 15s after releasing Resonance Skill.'),
(6, 'Sierra Gale', '2-Pc', 'Aero DMG + 10%.', '5-Pc', 'Aero DMG + 30% for 15s after releasing Intro Skill.'),
(7, 'Celestial Light', '2-Pc', 'Spectro DMG + 10%.', '5-Pc', 'Spectro DMG + 30% for 15s after releasing Intro Skill.'),
(8, 'Havoc Eclipse', '2-Pc', 'Havoc DMG + 10%.', '5-Pc', 'Havoc DMG + 7.5% after releasing Basic Attack or Heavy Attack. This effect stacks up to 4 times, each stack lasts 15s.'),
(9, 'Freezing Frost', '2-Pc', 'Glacio DMG + 10%.', '5-Pc', 'Glacio DMG + 10% after releasing Basic Attack or Heavy Attack. This effect stacks up to 3 times, each stack lasts 15s.'),
(10, 'Frosty Resolve', '2-Pc', 'Resonance Skill DMG + 12%', '5-Pc', 'Casting Resonance Skill grants 22.5% Glacio DMG Bonus for 15s and casting Resonance Liberation increases Resonance Skill DMG by 18%, lasting for 5s. This effect stacks up to 2 times.'),
(11, 'Empyrean Anthem', '2-Pc', 'Energy Regen + 10%', '5-Pc', 'Increase the Resonator\'s Coordinated Attack DMG by 80%. Upon a critical hit of Coordinated Attack, increase the active Resonator\'s ATK by 20% for 4s.'),
(12, 'Midnight Veil', '2-Pc', 'Havoc DMG + 10%', '5-Pc', 'When Outro Skill is triggered, deal additional 480% Havoc DMG to surrounding enemies, considered Outro Skill DMG, and grant the incoming Resonator 15% Havoc DMG Bonus for 15s.'),
(13, 'Eternal Radiance', '2-Pc', 'Spectro DMG + 10%', '5-Pc', 'Inflicting Spectro Frazzle on enemies increases Crit. Rate by 20% for 15s. Attacking enemies inflicted with 10 stacks of Spectro Frazzle grants 15% Spectro DMG Bonus for 15s.'),
(14, 'Tidebreaking Courage', '2-Pc', 'Energy Regen + 10%', '5-Pc', 'Increase the Resonator\'s ATK by 15%. Reaching 250% Energy Regen increases all Attribute DMG by 30% for the Resonator.'),
(15, 'Dream of the Lost', '3-Pc', 'Holding 0 Resonance Energy increases Crit. Rate by 20% and grants 35% Echo Skill DMG Bonus.', '', ''),
(16, 'Flamewing\'s Shadow', '3-Pc', 'Dealing Echo Skill DMG increases Heavy Attack Crit. Rate by 20% for 6s. Dealing Heavy Attack DMG increases Echo Skill Crit. Rate by 20% for 6s. While both effects are active, gain 16% Fusion DMG Bonus.', '', ''),
(17, 'Thread of Severed Fate', '3-Pc', 'Inflicting Havoc Bane increases the Resonator\'s ATK by 20% and grants 30% Resonance Liberation DMG Bonus for 5s.', '', ''),
(18, 'Law of Harmony', '3-Pc', 'Casting Echo Skill grants 30% Heavy Attack DMG Bonus to the caster for 4s. Additionally, all Resonators in the team gain 4% Echo Skill DMG Bonus for 30s, stacking up to 4 times. Echoes of the same name can only trigger this effect once. The record of Echo triggering this effect is cleared along with this effect. At 4 stacks, casting Echo Skill again resets the duration of this effect.', '', ''),
(19, 'Crown of Valor', '3-Pc', 'Upon gaining a Shield, increase the Resonator\'s ATK by 6% and Crit. DMG by 4% for 4s. This effect can be triggered once every 0.5s and stacks up to 5 times.', '', ''),
(20, 'Gusts of Welkin', '2-Pc', 'Aero DMG + 10%', '5-Pc', 'Inflicting Aero Erosion upon enemies increases Aero DMG for all Resonators in the team by 15%, and for the Resonator triggering this effect by an additional 15%, lasting for 20s.'),
(21, 'Flaming Clawprint', '2-Pc', 'Fusion DMG + 10%', '5-Pc', 'Casting Resonance Liberation grants all Resonators in the team 15% Fusion DMG Bonus and the caster 20% Resonance Liberation DMG Bonus, lasting for 35s.'),
(22, 'Windward Pilgrimage', '2-Pc', 'Aero DMG + 10%', '5-Pc', 'Hitting a target with Aero Erosion increases Crit. Rate by 10% and grants 30% Aero DMG Bonus, lasting for 10s.'),
(23, 'Halo of Starry Radiance', '2-Pc', 'Healing Bonus + 10%.', '5-Pc', 'When healing a Resonator in the team, every 1% of Off-Tune Buildup Rate grants a 0.2% ATK increase to all Resonators in the team for 4s, up to 25%. Effects of the same name cannot be stacked.'),
(24, 'Chromatic Foam', '2-Pc', 'Fusion DMG + 10%', '5-Pc', 'When the Resonator inflicts Fusion Burst on the enemies, they gain the following effects: Gain 10% Fusion DMG Bonus for 15 s. While this effect is active, casting an Outro Skill grants the incoming Resonator 25% Fusion DMG Bonus for 15s.'),
(25, 'Pact of Neonlight Leap', '2-Pc', 'Spectro DMG + 10%', '5-Pc', 'Casting Outro Skill increases the ATK of the incoming Resonator who casts Intro Skill by 15%. Each point of Tune Break Boost the incoming Resonator has additionally increases their ATK by 0.3%, up to 15%. This effect lasts for 15s, or until the Resonator is switched out.'),
(26, 'Rite of Gilded Revelation', '2-Pc', 'Spectro DMG + 10%', '5-Pc', 'Dealing Basic Attack DMG increases Spectro DMG by 10% for 5s, stacking up to 3 times. With 3 stacks, casting Resonance Liberation grants 40% Basic Attack DMG Bonus.'),
(27, 'Sound of True Name', '2-Pc', 'Aero DMG + 10%', '5-Pc', 'Dealing Echo Skill DMG to enemies increases the Resonator\'s Echo Skill Crit. Rate by 20%, and grants 15% Aero DMG Bonus for 5s.'),
(28, 'Trailblazing Star', '2-Pc', 'Fusion DMG + 10%', '5-Pc', 'Inflicting Fusion Burst or Tune Rupture - Shifting increases the Resonator\'s Crit. Rate by 20% and grants 20% Fusion DMG Bonus for 8s.');
INSERT INTO `weapons` (`id`, `name`, `type`, `rarity`, `main_stat`, `image_url`, `description`, `story`, `atk_base`, `atk_max`, `stat_base`, `stat_max`, `mat_1_t1`, `mat_1_t2`, `mat_1_t3`, `mat_1_t4`, `mat_2_t1`, `mat_2_t2`, `mat_2_t3`, `mat_2_t4`, `skill_name`) VALUES
(191, 'Lustrous Razor', 'Broadblade', 5, 'ATK%', 'wp_lustrous_razor.png', 'Increases Energy Regen by [12.8, 3.2]%. When Resonance Skill is cast, Resonance Liberation DMG Bonus is increased by [7, 1.75]%, stacking up to 3 times. This effect lasts for 12s.', 'A broadblade incorporating advanced technologies. It responds to the wielder’s frequency and unleashes a destructive energy blade that can tear through the night.', 47, 587, '8.10%', '36.40%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Stormy Resolution'),
(192, 'Emerald of Genesis', 'Sword', 5, 'Crit Rate%', 'wp_emerald_of_genesis.png', 'Increases Energy Regen by [12.8, 3.2]%. When Resonance Skill is cast, increases ATK by [6, 1.5]%, stacking up to 2 time(s). This effect lasts for 10s.', 'Pay heed: the frigid blade reveals an icy current, amalgamating into a whirlpool of thoughts. Use this powerful sequence to effortlessly crush your enemies with the Sword.', 47, 587, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip\r\n', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Stormy Resolution'),
(193, 'Static Mist', 'Pistols', 5, 'Crit Rate%', 'wp_static_mist.png', 'Increases Energy Regen by [12.8, 3.2]%. Incoming Resonator\'s ATK is increased by [10, 2.5]% for 14s, stackable for up to 1 times after the wielder casts Outro Skill.', 'Grip the sleek frame and feel its cool surface as you aim down the sight. With a pull of the trigger, unleash a thick smoke barrage onto the battlefield with these powerful Pistols in your hands.', 47, 587, '5.40%', '24.30%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Stormy Resolution'),
(194, 'Abyss Surges', 'Gauntlets', 5, 'ATK%', 'wp_abyss_surges.png', 'Increases Energy Regen by [12.8, 3.2]%. When hitting a target with Resonance Skill, increases Basic Attack DMG Bonus by [10, 2.5]%, lasting for 8s. When hitting a target with Basic Attacks, increases Resonance Skill DMG Bonus by [10, 2.5]%, lasting for 8s.', 'The Gauntlets pulsate with an uncontrollable force, emanating unspeakable anger from the depths of the unknown lake. As you don them, unleash your fury on helpless enemies. Feel its power surge through you.', 47, 587, '8.10%', '36.45%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Stormy Resolution'),
(195, 'Cosmic Ripples', 'Rectifier', 5, 'ATK%', 'wp_cosmic_ripples.png', 'Increases Energy Regen by [12.8, 3.2]%. When dealing Basic Attack DMG, increases Basic Attack DMG Bonus by [3.2, 0.8]%, stacking up to 5 time(s). This effect lasts for 8s and can be triggered 1 time(s) every 0.5s.', 'Take hold of the frozen Rectifier, a powerful tool imbued with the energy of the celestial lake. Let it lead you to ultimate knowledge and vanquish all obstacles in your path.', 40, 500, '12.00%', '54.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Stormy Resolution'),
(196, 'Verdant Summit', 'Broadblade', 5, 'Crit DMG%', 'wp_verdant_summit.png', 'Increases Attribute DMG Bonus by [12, 3]%. Every time Intro Skill or Resonance Liberation is cast, increases Heavy Attack DMG Bonus by [24, 6]%, stacking up to 2 time(s). This effect lasts for 14s.', 'The ancient mountain stands tall, its peak reaching towards the sky. A river flows for thousands of years, forming the blade of a powerful weapon. As it is unsheathed, a powerful dragon\'s roar echoes through the heavens and earth, causing the sea to churn. This awe-inspiring weapon strikes fear in all who witness its might.', 47, 587, '10.80%', '48.60%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core\r\n', 'HF Whisperin Core', 'FF Whisperin Core', 'Swordsworn'),
(197, 'Stringmaster', 'Rectifier', 5, 'Crit Rate%', 'wp_stringmaster.png', 'Grants [12, 3]% Attribute DMG Bonus. When dealing Resonance Skill DMG, increases ATK by [12, 3]%, stacking up to 2 times. This effect lasts for 5s. When the wielder is not on the field, increases their ATK by an additional [12, 3]%.', 'The puppet\'s palm unfurls, releasing deadly strings with a menacing hum. The air crackles, immobilizing foes and leaving unhealable scars from rapid electric bolts.', 40, 500, '8.00%', '36.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Electric Amplification'),
(198, 'Ages of Harvest', 'Broadblade', 5, 'Crit Rate%', 'wp_ages_of_harvest.png', 'Grants [12, 3]% Attribute DMG Bonus. Casting Intro Skill gives the equipper Ageless Marking, which grants [24, 6]% Resonance Skill DMG Bonus for 12s. Casting Resonance Skill gives the equipper Ethereal Endowment, which grants [24, 6]% Resonance Skill DMG Bonus for 12s.', 'Each swing of the blade reveals the flow of time and the change of the stars. The sword embodies all things, uniting them into one. Its gentle aura seems capable of dissolving the indestructible, whether it\'s millennia-old ice or the stagnation of time.', 47, 587, '5.40%', '24.30%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core\r\n', 'FF Whisperin Core', 'Divine Blessing'),
(199, 'Blazing Brilliance', 'Sword', 5, 'Crit DMG%', 'wp_blazing_brilliance.png', 'ATK increased by [12, 3]%. The wielder gains 1 stack of Searing Feather upon dealing damage, which can be triggered once every 0.5s, and gains 5 stacks of the same effect upon casting Resonance Skill. Each stack of Searing Feather gives [4, 1]% additional Resonance Skill DMG Bonus for up to 14 stacks. After reaching the max stacks, all stacks will be removed in 12s.\r\n\r\n', 'Forged from the very essence and feathers of a legendary bird, this weapon blazes with an intensity that bathes the world in its luminous glow. With each fiery surge, it consumes all in its path, leaving nothing but ashes in its wake.', 47, 587, '10.80%', '48.60%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Crimson Phoenix'),
(200, 'Rime-Draped Sprouts', 'Rectifier', 5, 'Crit DMG%', 'wp_rime_draped_sprouts.png', 'Increase ATK by [12, 3]%. While the wielder is on the field, using Resonance Skill grants [12, 3]% Basic Attack DMG Bonus, stacking up to 3 times for 6s. At 3 stacks or above, casting Outro Skill consumes all stacks of this effect and grants the wielder [52, 13]% Basic Attack DMG Bonus for 27s, effective when the wielder is off the field.', 'An artist\'s seal adorned with rimed sprouts. It is stamped on numerous paintings that capture mountains and ravines in expressive, mesmerizing strokes. The tender sprouts symbolize the perpetual blossoming of artistic marvels.', 40, 500, '16.00%', '72.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring\r\n', 'Panorama'),
(201, 'Verity\'s Handle', 'Gauntlets', 5, 'Crit Rate%', 'wp_verity_s_handle.png', 'Gain [12, 3]% Attribute DMG Bonus. When using Resonance Liberation, the wielder gains [48, 12]% Resonance Liberation DMG Bonus for 8s. This effect can be extended by 5s each time Resonance Skills are cast, up to 3 times.', 'Crafted with the lost art from the Court of Savantae, these gauntlets are solid and unbreakable, despite their lightweight materials. They are no tools of violence or aggression, but instruments for unraveling puzzles and pursuing the truth.', 47, 587, '5.40%', '24.30%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ad Veritatem'),
(202, 'Stellar Symphony', 'Rectifier', 5, 'Energy Regen%', 'wp_stellar_symphony.png', 'Increase HP by [12, 3]%. Restore [8, 2] Concerto Energy when casting Resonance Liberation. This effect can be triggered 1 time(s) every 20s. When casting Resonance Skill that heals, increase nearby party members\' ATK by [14, 3.5]% for 30s. Effects of the same name cannot be stacked.', 'A rectifier bearing an energy core that simulates the lifecycle of stars—an infinite loop that originates from a singularity and ends in explosive demise. The celestial debris collides in thunderous rumbles, heralding the birth of a new star.', 27, 412, '8.0%', '77.04%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Astral Evolvement'),
(203, 'Red Spring', 'Sword', 5, 'Crit Rate%', 'wp_red_spring.png', 'Increase ATK by [12, 3]%. When dealing Basic Attack DMG, the wielder gains [10, 2.5]% Basic Attack DMG Bonus for 14s. This effect can be triggered once per second, stacking up to 3 times. When the wielder\'s Concerto Energy is consumed, gain [40, 10]% Basic DMG Bonus for 10. This effect can be triggered once per second and ends when the wielder is switched off the field.', 'A camellia bud silently unfurls. As promised, she holds this infinite world in bloom in her palms, where fine crimson vines twine around her fingertips. The dull ache, like sand scratching against the heart, is proof of your fateful encounter.', 47, 587, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Beyond the Cycle'),
(204, 'Tragicomedy', 'Gauntlets', 5, 'Crit Rate%', 'wp_tragicomedy.png', 'Increases ATK by [12, 3]%. Every time Basic Attack or Intro Skill is cast, Heavy Attack DMG Bonus increases by [48, 12]% for 3s.', 'The joys and sorrows of life dance in an endless circle; Pain and tears shift in an instant into a carnival.', 47, 587, '5.40%', '24.30%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Fool\'s Warble'),
(205, 'The Last Dance', 'Pistols', 5, 'Crit DMG%', 'wp_the_last_dance.png', 'Increases ATK by [12, 3]%. Every time Intro Skill or Resonance Liberation is cast, Resonance Skill DMG Bonus increases by [48, 12]% for 5s.', 'The radiant crystals, ever shattering and reshaping, beckon you into a treacherous dance, a gamble where life is the wager. Cortado, cortado... relentlessly draw each other in until all we can hear are our quivers. When the crimson finale arrives, remember, death comes for all.\r\n\r\n', 40, 500, '16.00%', '72.00%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Silent Eulogy'),
(206, 'Unflickering Valor', 'Sword', 5, 'Energy Regen%', 'wp_unflickering_valor.png', 'Increase Crit. Rate by [8, 2]%. Casting Resonance Liberation gives [24, 6]% Basic Attack DMG Bonus for 10s. Dealing Basic Attack DMG gives [24, 6]% Basic Attack DMG Bonus for 4s.', 'Blistering winds and crashing waves, the sea devours all. Only a lonely boat lamp stands alight! Onwards! Towards the edge of the world you shall sail!', 33, 412, '17.12%', '77.04%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Laughter Prevails'),
(207, 'Luminous Hymn', 'Rectifier', 5, 'Crit Rate%', 'wp_luminous_hymn.png', 'Increase ATK by [12, 3]%. Dealing DMG to targets with Spectro Frazzle grants the wielder [14, 3.5]% Basic Attack DMG Bonus and [14, 3.5]% Heavy Attack DMG Bonus, stacking up to 3 for 6s. Casting Outro Skill Amplifies the Spectro Frazzle DMG on targets around the active Resonator by [30, 7.5]% for 30s. Effects of the same name cannot be stacked.', '\"The Sentinel\'s grace, how sweet thou art. Our home was lost, but found at last. With twigs between my beaks, I brave the waves. Bound by love, we\'re crowned with holy light.\"', 40, 500, '8.00%', '36.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Homebuilder\'s Anthem'),
(208, 'Whispers of Sirens', ' Rectifier', 5, 'Crit DMG%', 'wp_whispers_of_sirens.png', 'Increases ATK by [12, 3]%. Casting Echo Skill within 10s after casting Intro Skill or Basic Attacks grants 1 of Gentle Dream. Echoes with the same name can only trigger this effect once, stacking up to 2 times, lasting for 10s. When reaching 2 stacks, casting Echo Skill no longer resets the duration of this effect. This effect activates up to once per 10s. Switching to another Resonator ends this effect early. With 1 : Grants [40, 10]% Basic Attack DMG Bonus. With 2 : Ignores [12, 3]% of the target\'s Havoc RES.', 'From the sea, some see stars, some catch the moon, and some hear countless whispers and murmurs. Those murmurs seep into her venom, flowing through every winding river. In the end, the murmurs envelope, like the bell of a jellyfish, like the sea.', 40, 500, '16.00%', '72.00%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring\r\n', 'Tailored Ring', 'From the Deep'),
(209, 'Bloodpact\'s Pledge', 'Sword', 5, ' Energy Regen%', 'wp_bloodpact_s_pledge.png', 'Providing Healing increases Resonance Skill DMG by [10, 4]% for 6s. When Rover: Aero casts Resonance Skill Unbound Flow, Aero DMG dealt by nearby Resonators on the field is Amplified by [10, 4]% for 30s.', 'This weapon is a testament to the unbreakable blood pact: One shall never betray, never surrender, and fight until the last drop of blood is shed.', 47, 587, '8.64%', '38.88%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Harmonious Vibrancy'),
(210, 'Blazing Justice', 'Gauntlets', 5, 'Crit DMG%', 'wp_blazing_justice.png', 'Increases ATK by [12, 3]%. Casting Basic Attack grants the following effects: Dealing damage ignores [8, 2]% of the target\'s DEF and Amplifies Spectro Frazzle DMG dealt by [50, 12.5]% for 6s. Retriggering the effect resets its duration.', 'It heralds justice, precise and inexorable as a clock\'s toll. All sins are cleansed in flame, dissipating like night beneath the dawn\'s gaze.\r\n\r\n', 47, 587, '10.80%', '48.60%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Darkness Breaker'),
(211, 'Woodland Aria', 'Pistols', 5, 'Crit Rate%', 'wp_woodland_aria.png', 'ATK is increased by [12, 3]%. Inflicting Aero Erosion on the target gives [24, 6]% Aero DMG Bonus for 10s. Hitting targets with Aero Erosion reduces their Aero RES by [10, 1.5]% for 20s. Effects of the same name cannot be stacked.', 'All things exist within the lines of poetry. Every sound has its meters and rhymes. The forest\'s melodies ascend in spirals toward the moon\'s silvered grace, harmonized by the nightingales\' chorus. When the final note falls and vanishes into the silent earth, a flawless chord echoes endlessly in the depths of this boundless realm.', 40, 500, '8.00%', '36.00%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Lingering Summer Tune'),
(212, 'Defier\'s Thorn', 'Sword', 5, 'HP%', 'wp_defier_s_thorn.png', 'Max HP is increased by [12, 3]%. 15s after casting Intro Skill or Basic Attacks, ignore [8, 2]% of the target\'s DEF when dealing damage. If the target has at least 1 stack of Aero Erosion, the DMG taken by the target is Amplified by [20, 5]%.', 'The surging tides force the crown of thorns upon the knight, out of which the knight forges this sword. Unburdened by the crown, the knight waded through the roaring waves unwaveringly.', 33, 412, '16.05%', '72.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip\r\n', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'A Free Knight\'s Tarantella'),
(213, 'Wildfire Mark', 'Broadblade', 5, 'Crit DMG%', 'wp_wildfire_mark.png', 'Increases ATK by [12, 3]%. Performing Intro Skill or Resonance Liberation increases Resonance Liberation DMG by [24, 6]% for 6s. Dealing Heavy Attack DMG extends this effect by 4s, up to 1 time. Each successful extension gives [24, 6]% Fusion DMG Bonus to all Resonators in the team for 30s. Effects of the same name cannot be stacked.', 'The young wolf races through the wilds, shedding every shadow that once held her back. The lone wolf strides into the arena, cutting down each obstacle in her path. She seizes victory. She claims glory. She raises everything she has high above. She belongs to the arena, but even more, she belongs to herself.', 47, 587, '10.80%', '48.60%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Blazing Starfire'),
(214, 'Lethean Elegy', 'Rectifier', 5, 'Crit Rate%', 'wp_lethean_elegy.png', 'ATK is increased by [12, 3]%. Within 12s after dealing Echo Skill DMG, gain [32, 8]% Resonance Skill DMG Bonus and [32, 8]% Echo Skill DMG Amplification, and ignore [8, 2]% of the target\'s DEF when dealing damage.', 'I am not there. I do not die. I shall be death\'s companion—with euphoric delights I drown my fear, with the coming days I trade for the past.', 47, 587, '5.40%', '24.30%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Underworld Requiem'),
(215, 'Moongazer\'s Sigil', 'Gauntlets', 5, 'Crit Rate%', 'wp_moongazer_s_sigil.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or Resonance Liberation increases Resonance Liberation DMG by [20, 5]% for 15s. Obtaining Shield allows Resonance Liberation DMG to ignore [7.2, 1.2]% of the target\'s DEF for 7s, stacking up to 5 times. This effect is triggered once every 0.5s. Upon casting Intro Skill, this effect reaches max stacks immediately, lasting for 3s.', 'By what means do all things endure? By light and heat, by matter and word, by the mechanics of converging chances, by the soft dissolution into silence, by a moment that mimics the eternal... All things rise and fall in endless rhythm, each bearing its meaning. As for hers, it lies here within her grasp.\r\n\r\n', 40, 500, '8.00%', '36.00%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Plenilune Radiance'),
(216, 'Thunderflare Dominion', 'Broadblade', 5, 'Crit Rate%', 'wp_thunderflare_dominion.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or Resonance Skill increases Heavy Attack DMG by [20, 5]% for 15s. Obtaining Shield allows Heavy Attack DMG to ignore [7.2, 1.2]% of the target\'s DEF for 7s, stacking up to 5 times. This effect is triggered once every 0.5s', 'Thunder shall purge her pain and weakness. From the crucible of blood and sand, the Sun rises. Not dimmed by dust, but ablaze in her full radiance.', 54, 675, '2.70%', '12.15%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core\r\n', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Thunderblaze Eminence'),
(217, 'Lux & Umbra', 'Pistols', 5, 'Crit DMG%', 'wp_lux_umbra.png', 'ATK is increased by [12, 3]%. Upon dealing Echo Skill DMG, gain [24, 6]% Heavy Attack DMG Amplification for 6s. Upon dealing Heavy Attack DMG, gain [24, 6]% Echo Skill DMG Amplification for 6s. DMG Amplification on each attack is capped at [24, 6]%. While both effects are active, dealing damage ignores [8, 2]% of the target\'s DEF.', 'From darkness she seizes power, layering sins upon herself. To hunt. To kill. To deliver a relentless and fatal blow to all evil. From the light she falls, with her vows etched in her mind. For the deceased. For the living. For her pistols\' true targets.\r\n\r\n', 47, 587, '10.80%', '48.60%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston\r\n', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'To Fire She Returns'),
(218, 'Emerald Sentence', 'Sword', 5, 'Crit Rate%', 'wp_emerald_sentence.png', 'ATK is increased by [12, 3]%. Casting Echo Skill within 10s after casting Intro Skill or Basic Attack grants 1 stack of Bamboo Cleaver, which grants [30, 7.5]% Heavy Attack DMG Bonus to the wielder. This effect can be triggered by Echoes of the same name once only, stacking up to 2 times, lasting for 12s. Casting Echo Skill at max stacks does not reset the duration. This effect can be triggered once every 10s and ends early if the wielder is switched off the field. Casting Intro Skill grants [20, 5]% Echo Skill DMG Bonus to all Resonators in the team for 30s. Effects of the same name cannot be stacked.', 'Bamboo, hollow yet full; People, whole yet seldom true. Bamboo speaks without deceit, acts without conceit, seeks no vanity. Few ever measure up thus.', 47, 587, '5.40%', '24.30%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip\r\n', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'When A Heart Settles'),
(219, 'Kumokiri', 'Broadblade', 5, 'Crit Rate%', 'wp_kumokiri.png', 'ATK is increased by [12, 3]%. When the wielder casts Intro Skill or inflicts Negative Statuses, they gain [8, 2]% Resonance Liberation DMG Bonus, stacking up to 3 times for 15s. At max stacks, when Resonators in the team inflict Negative Statuses, they gain [24, 6]% All-Attribute DMG Bonus for 15s. Effects of the same name cannot be stacked.', 'A crimson thread emerges in the void, as if binding the structures of all things onto a single thread. At her fingertips, the endless season is drawn taut, snipped, and rewoven, until the scattered path at last converges once more upon this timeline.', 40, 500, '8.00%', '36.00%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core\r\n', 'Thread of Fate'),
(220, 'Spectrum Blaster', 'Pistols', 5, 'Crit Rate%', 'wp_spectrum_blaster.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or dealing Basic Attack DMG to targets increases the wielder\'s Basic Attack DMG Bonus by [36, 9]% for 4s. Each time the wielder inflicts Tune Rupture - Shifting or Tune Strain - Shifting during Basic Attacks, all DMG dealt by Resonators in the team is increased by [8, 2]% for 30s, up to 3 stacks. Effects of the same name cannot be stacked.', 'Prismatic light dances at her fingertips, arcs of color carving radiant trails. Every rushing hue converges upon her aim, and at last, she reaches a sky where nothing lies beyond her sight.', 47, 587, '5.40%', '24.30%', 'Incomplete Combustor', 'Aftertune Combustor', 'Remnant Combustor', 'Reverb Combustor', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Attendance Exemption Protocol'),
(221, 'Starfield Calibrator', 'Broadblade', 5, 'Energy Regen%', 'wp_starfield_calibrator.png', 'Increases DEF by [16, 4]%. Casting Resonance Skill restores [8, 2] points of Concerto Energy. This effect can be triggered 1 every 20s. When the wielder heals Resonators, increases Crit. DMG of all nearby Resonators in the team by [20, 5]% for 4s. Effects of the same name cannot be stacked.', 'Every pattern can be observed. Every phenomenon can be understood. The ideal may lie light-years away, yet the path toward it rests within her own hands.', 33, 412, '17.12%', '77.04%', 'LF Carved Crystal\r\n', 'MF Carved Crystal', 'HF Carved Crystal', 'FF Carved Crystal', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Definite Solution'),
(222, 'Radiance Cleaver', 'Broadblade', 5, 'Crit DMG%', 'wp_radiance_cleaver.png', 'Increases ATK by [12, 3]%. Dealing damage to targets under Tune Strain - Interfered grants [24, 3]% Resonance Liberation Bonus for 3s. Retriggering the effect resets its duration.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-BB325042 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. The light patterns along the blade shift in response to the wielder\'s frequency fluctuations. It crystallizes reason into a concentrated force—a tool to cut through obstacles as well as a measure for charting the unknown. Ideal for the edge breakers who carve their path forward with unwavering resolve.', 47, 587, '10.80%', '48.60%', 'LF Carved Crystal', 'MF Carved Crystal', 'HF Carved Crystal\r\n', 'FF Carved Crystal', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Edge Breaker'),
(223, 'Laser Shearer', 'Sword', 5, ' Energy Regen%', 'wp_laser_shearer.png', 'Increases ATK by [12, 3]%. Dealing damage to targets under Tune Strain - Interfered grants [24, 3]% Resonance Skill Bonus for 3s. Retriggering the effect resets its duration.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-SWD201052 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. The light patterns along the blade shift in response to the wielder\'s frequency fluctuations. Each strike expresses a refined intuition, a \"razor\" that cuts away unnecessary possibilities. Ideal for the signal catchers who discern the greater picture from the smallest details and make sound judgments.', 47, 587, '8.64%', '38.88%', 'Broken Wing Polarizer', 'Monowing Polarizer', 'Polywing Polarizer', 'Layered Wing Polarizer', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Signal Catcher'),
(224, 'Phasic Homogenizer', 'Pistols', 5, 'Crit DMG%', 'wp_phasic_homogenizer.png', 'Increases ATK by [12, 3]%. After a Resonator in the team casts a Tune Break skill, it grants [20, 2.5]% All-Attribute DMG Bonus to the wielder for 14s.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-PSTL325052 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. Projectile and rifling are spectrally tuned to unleash a potent frequency disturbance on impact, exposing and shattering a target\'s weak points. It serves as both a benchmark of precision and a weapon that pierces with unwavering focus. Ideal for insight bearers who act with deliberate caution and perceive what others overlook.', 47, 587, '10.80%', '48.60%', 'Incomplete Combustor', 'Aftertune Combustor', 'Remnant Combustor', 'Reverb Combustor', 'Fractured Exoswarm Pendant', 'Worn Exoswarm Pendant', 'Chipped Exoswarm Pendant', 'Intact Exoswarm Pendant', 'Insight Bearer'),
(225, 'Pulsation Bracer', 'Gauntlets', 5, 'Crit Rate%', 'wp_pulsation_bracer.png', 'Increases ATK by [12, 3]%. Dealing damage to targets under Tune Strain - Interfered grants [6, 0.7]% Basic Attack DMG Bonus for 3s, stacking up to 4 times. This effect can be triggered 1 every 0.5s. Retriggering the effect resets its duration.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-GNTL522152 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. The armor\'s spectrum shifts as it restores kinetic energy. The Pulsation Bracer predicts the wearer\'s stance to amplify the stored reactive torque and release it in a single, instantaneous surge—a decisive force delivered at the critical moment. Ideal for the barrier breachers who advance with steady resolve and stand unshaken under pressure.\r\n\r\n', 47, 587, '5.40%', '24.30%', 'LF Waveworn Shard', 'MF Waveworn Shard', 'HF Waveworn Shard', 'FF Waveworn Shard', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Barrier Breacher'),
(226, 'Boson Astrolabe', 'Rectifier', 5, 'Energy Regen%', 'wp_boson_astrolabe.png', 'Increases ATK by [12, 3]%. After a Resonator in the team casts a Tune Break skill, it grants a [12, 1.5]% ATK increase and [12, 1.5]% Basic Attack DMG Bonus to the wielder for 14s.', 'Spacetrek Collective \"Synth Armament\" Series Model: SCSA-LHRi-RCTF325062 Forged from compound technology that fuses Exostrider biomorphic components with Tacetite, this weapon offers two core features: frequency auto-adaptation and user binding. Its power scales directly with the wielder\'s Forte, growing sharper through dedicated Forte training. Composed of a spectral ring-lens and layered glass plates, the device captures even the faintest frequency shifts. Like a guiding star that leads the seekers through a sea of tangled thoughts, it maps possibilities before they take shape. Ideal for the path observers who perceive the world a step ahead.', 42, 525, '8.64%', '38.88%', 'Spliced String', 'Broken String', 'Solidified String', 'Melodic String', 'LF Exoswarm Core', 'MF Exoswarm Core', 'HF Exoswarm Core', 'FF Exoswarm Core', 'Path Observer\r\n'),
(227, 'Everbright Polestar', 'Sword', 5, 'Crit Rate%', 'wp_everbright_polestar.png', 'Increases All-Attribute DMG Bonus by [12, 3]%. When inflicting Tune Rupture - Shifting or Fusion Burst, the wielder\'s Resonance Liberation DMG ignores [32, 8]% DEF and [10, 5]% Fusion RES on targets for 8s.', 'As you drift across the hushed sea of stars, stardust scatters beside you as time crumbles in your wake. All that remains is the unyielding loneliness, warped, diluted, and remade into the plumes of your wings. The universe sends you on a tribulation of silence, yet you travel on, repaying in radiance.', 47, 587, '5.40%', '24.30%', 'Broken Wing Polarizer', 'Monowing Polarizer', 'Polywing Polarizer', 'Layered Wing Polarizer', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Starchaser'),
(228, 'Daybreaker\'s Spine', 'Gauntlets', 5, 'Crit Rate%', 'wp_daybreaker_s_spine.png', 'Increases ATK by [12, 3]%. After dealing Basic Attack DMG, the wielder gains [20, 5]% Spectro DMG Bonus for 4s. Each time after the wielder inflicts Tune Strain - Shifting on the target, they gain [20, 5]% Basic Attack DMG Amplification and their Basic Attack DMG ignores [10, 2.5]% of the target\'s DEF for 6s.', 'Those are not ridges of the mountains, but the spine of the earth, carrying the night. They protrude from the abdomen of darkness. From the incision spills the light of new life. Your shadow was nailed to the dying night. With the breaking dawn, your flesh shall rise. Let it knock open every door of denial.', 47, 587, '5.40%', '24.30%', 'LF Waveworn Shard', 'MF Waveworn Shard', 'HF Waveworn Shard', 'FF Waveworn Shard', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Suturing Dayline'),
(229, 'Solsworn Ciphers', 'Gauntlets', 5, 'Crit DMG%', 'wp_solsworn_ciphers.png', 'Increases ATK by [12, 3]%. Casting Intro Skill or Echo Skill grants [32, 8]% Echo Skill DMG Amplification for 15s. When dealing Echo Skill DMG, Aero DMG ignores [10, 2.5]% of the target\'s DEF for 6s.', 'Sunlight gathers. The answer is made plain. What must be done awaits. The Rein is in your hand. Step forward, toward the sunlit end.', 47, 587, '10.80%', '48.60%', 'LF Waveworn Shard', 'MF Waveworn Shard', 'HF Waveworn Shard', 'FF Waveworn Shard', 'LF Mech Core', 'MF Mech Core', 'HF Mech Core', 'FF Mech Core', 'Sunward'),
(231, 'Autumntrace', 'Broadblade', 4, 'Crit Rate%', 'wp_autumntrace.png', 'Increases ATK by [4, 2.2]% upon dealing Basic Attack DMG or Heavy Attack DMG, stacking up to 5 time(s). This effect lasts for 7s and can be triggered 1 time(s) every 1s.', 'This Broadblade is a ceremonial weapon used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 33, 412, '4.50', '20.25%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core\r\n', 'FF Whisperin Core\r\n', 'Edge Direction'),
(232, 'Lumingloss', 'Sword', 4, 'ATK%', 'wp_lumingloss.png', 'When Resonance Skill is cast, increases Basic Attack DMG Bonus and Heavy Attack DMG Bonus by [20, 11]%, stacking up to 1 time(s). This effect lasts for 10s and can be triggered 1 time(s) every 1s.', 'This Sword is a ceremonial weapon used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 31, 387, '8.10%', '36.45%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Pale Gale'),
(233, 'Thunderbolt', 'Pistols', 4, 'ATK%', 'wp_thunderbolt.png', 'When hitting a target with Basic Attacks or Heavy Attacks, increases Resonance Skill DMG Bonus by [7, 4]%, stacking up to 3 time(s). This effect lasts for 10s and can be triggered 1 time(s) every 1s.', 'These Pistols are ceremonial weapons used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 31, 387, '8.10%', '36.45%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Unstoppable'),
(234, 'Stonard', 'Gauntlets', 4, 'Crit Rate%', 'wp_stonard.png', 'Casting Resonance Skill increases the wielder\'s Resonance Liberation DMG Bonus by [18, 9]%, lasting for 15s.', 'These Gauntlets are ceremonial weapons used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 33, 412, '4.50%', '20.25%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Wallbreaker'),
(235, 'Augment', 'Rectifier', 4, 'Crit Rate%', 'wp_augment.png', 'Casting Resonance Liberation increases the wielder\'s ATK by [15, 8.25]%, lasting for 15s.', 'This Rectifier is a ceremonial weapon used in Huanglong\'s Magistrate Inauguration Ceremonies. The golden ginkgo leaf pattern symbolizes Huanglong\'s resilience, thriving in a world that has left it behind.', 33, 412, '4.50%', '20.25%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring\r\n', 'Tailored Ring', 'Forgiving Resilience'),
(236, 'Discord', 'Broadblade', 4, 'Energy Regen%', 'wp_discord.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 time(s) every 20s.', 'A descending adagio. This broadblade dominates the battlefield with the power of discordance. The curtain never falls on a masterpiece.', 27, 337, '11.52%', '51.84%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Ceaseless Aria'),
(237, 'Overture', 'Sword', 4, 'Energy Regen%', 'wp_overture.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 time(s) every 20s.', 'An ascending crescendo. This enchanting sword effortlessly cuts through anything in its way, like a glorious prelude.', 27, 337, '11.52%', '51.84%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ceaseless Aria'),
(238, 'Cadenza', 'Pistols', 4, 'Energy Regen%', 'wp_cadenza.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'An ascending crescendo. These pistols unleash bullets with the force of thunder, tearing through the heavens like a symphony of destruction.', 27, 337, '11.52%', '51.84%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ceaseless Aria'),
(239, 'Marcato', 'Gauntlets', 4, 'Energy Regen%', 'wp_marcato.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'A descending adagio. These gauntlets pulsate with the power of surging waves, shattering anything in their path like a deadly hymn.', 27, 337, '11.52%', '51.84%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Ceaseless Aria'),
(240, 'Variation', 'Rectifier', 4, 'Energy Regen%', 'wp_variation.png', 'When Resonance Skill is cast, restores [8, 2] Concerto Energy. This effect can be triggered 1 times every 20s.', 'A descending adagio. This rectifier opens up an insightful window into the situation, changing the tune of the intense battle concerto.', 27, 337, '11.52%', ' 51.84%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ceaseless Aria'),
(241, 'Broadblade#41', 'Broadblade', 4, 'Energy Regen%', 'wp_broadblade_41.png', 'When the Resonator\'s HP is above 80%, increases ATK by [12, 3]%. When the Resonator\'s HP is below [40, 10]%, gives [5, 1.25]% healing when dealing Basic Attack DMG or Heavy Attack DMG. This effect can be triggered 1 time(s) every 8s.', 'An improved version of a mass-produced broadblade model developed in Huanglong. With its formidable performance and innovative technologies, this broadblade carries a weight only to be wielded by seasoned warriors.', 33, 412, '7.20%', '32.40%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core\r\n', 'MF Whisperin Core\r\n', 'HF Whisperin Core\r\n', 'FF Whisperin Core\r\n', 'Veteran'),
(242, 'Sword#18', 'Sword', 4, 'ATK', 'wp_sword_18.png', 'When the Resonator\'s HP drops below [40, 10]%, increases Heavy Attack DMG Bonus by [18, 4.5]% and gives [5, 1.25]% healing when dealing Heavy Attack DMG. This effect can be triggered 1 time(s) every 8s.', 'An improved version of a mass-produced sword model developed in Huanglong. With its sleek blade and minimalist design, this sword is exclusively crafted for the skilled hands of seasoned warriors.', 31, 387, '8.10%', '36.45%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Daybreak'),
(243, 'Pistols#26', 'Pistols', 4, 'ATK%', 'wp_pistols_26.png', 'When the Resonator takes no damage, increases ATK by [6, 1.5]% every 5s, stacking up to 2 time(s). This effect lasts for 8s. When the Resonator takes damage, loses 1 stacks and heals [5, 1.25]% of their Max HP.', 'The Huaxu Academy has developed practical, high-performance pistols based on previous source energy weapons, showcasing their meticulous research and aiming for excellence.', 31, 387, '8.10%', '36.45%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Omniscient'),
(244, 'Gauntlets#21D', 'Gauntlets', 4, 'Energy Regen%', 'wp_gauntlets_21d.png', 'When the Resonator dashes or dodges, increases ATK by [8, 2]%. Increases Dodge Counter DMG by [50, 12.5]%, lasting for 8s. When Dodge Counter is performed, heals [5, 1.25]% of the Resonator\'s Max HP. This effect can be triggered 1 time(s) every 6s.', 'Huaxu Academy has independently improved and developed the first set of highly practical high-performance Gauntlets based on the previous source energy weapons, representing the care and warmth of the Academy, stable and lasting.', 31, 387, '8.64%', '38.88%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Mastermind'),
(245, 'Rectifier#25', 'Rectifier', 4, 'Energy Regen%', 'wp_rectifier_25.png', 'When Resonance Skill is cast, if the Resonator\'s HP is below 60%, heals [5, 1.25]% of their Max HP. This effect can be triggered 1 time(s) every 8s. If the Resonator\'s HP is above 60%, increases ATK by [12, 3]%, lasting for 10s.', 'An improved version of a Rectifier prototype from Huanglong\'s next-gen weaponry project. This device is characterized by its powerful, purified output and sound that resonates with the decisively strong-willed.', 27, 337, '11.52%', '51.84%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Dawnbringer'),
(246, 'Dauntless Evernight', 'Broadblade', 4, 'DEF%', 'wp_dauntless_evernight.png', 'When Intro Skill is cast, increases ATK by [8, 2]% and DEF by [15, 3.75]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' preparedness. \"Autumn fades in endless nights, ready blades gleam with silent might.\"', 27, 337, '13.68%', '61.56%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Battlebound'),
(247, 'Commando of Conviction', 'Sword', 4, 'ATK%', 'wp_commando_of_conviction.png', 'When Intro Skill is cast, increases ATK by [15, 3.75]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' courage. \"A thousand echoes carry the war\'s tale, as spirits unite in resounding gorges of valor.”', 33, 412, '6.75%', '30.38%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Unyielding'),
(248, 'Undying Flame', 'Pistols', 4, 'ATK%', 'wp_undying_flame.png', 'When Intro Skill is cast, increases Resonance Skill DMG Bonus by [20, 5]% for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' dedication. \"Let my body ablaze, flames dance to banish all evil\'s haze.\"', 33, 412, '6.75%', '30.38%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Loyalty'),
(249, 'Amity Accord', 'Gauntlets', 4, 'DEF%', 'wp_amity_accord.png', 'When Intro Skill is cast, increases Resonance Liberation DMG Bonus by [20, 5]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' comradeship. \"Thin garments yield to icy moons, while armor withstands the chill of stars.\"', 27, 337, '13.68%', '61.56%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Camaraderie'),
(250, 'Jinzhou Keeper', 'Rectifier', 4, 'ATK%', 'wp_jinzhou_keeper.png', 'Casting Intro Skill increases the wielder\'s ATK by [8, 2]% and HP by [10, 2.5]%, lasting for 15s.', 'A weapon designed to commemorate the Midnight Rangers\' vigilant protection of Jinzhou. \"Cast your gaze towards the north, where the city\'s silhouette fades, its gates veiled by the tranquil rain.\"\r\n\r\nContact us\r\nPrivacy Policy\r\nMarvel Rivals Tracker\r\nZZZ Characters\r\nCrimson Desert Database\r\nSub', 31, 387, '8.10%', '36.45%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Guardian'),
(251, 'Helios Cleaver', 'Broadblade', 4, 'ATK%', 'wp_helios_cleaver.png', 'Within 12s after Resonance Skill is cast, increases ATK by [3, 0.75]% every 2s, stacking up to 4 time(s). This effect can be triggered 1 time(s) every 12s. When the number of stacks reaches 4, all stacks will be reset within 6s.', 'The Broadblade born from the aerial phenomenon. The blacksmith incorporates the feelings of witnessing the alien star into the weapon, making it look hollow and light, but it can exert the invincible gravity of the starfall.', 33, 412, '6.75%', '30.38%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Plasma Recoiler'),
(252, 'Lunar Cutter', 'Sword', 4, 'ATK%', 'wp_lunar_cutter.png', 'Equipped Resonator gains 6 stack(s) of Oath upon entering the battlefield. Each stack increases ATK by [2, 0.5]%, up to 6 stacks. This effect can be triggered 1 time(s) every 12s. The equipped Resonator loses 1 stack(s) of Oath every 2s, and gains 6 stack(s) upon defeating an enemy.', 'The Sword born from the aerial phenomenon. The forger integrates the feelings of witnessing the alien star into the weapon, making it look light and sharp, but it can exert the energy of breaking the sky and cutting iron like mud.', 33, 412, '6.75%', '30.38%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Preordained'),
(253, 'Novaburst', 'Pistols', 4, 'ATK%', 'wp_novaburst.png', 'When the Resonator dashes or dodges, increases ATK by [4, 1]%, stacking up to 3 time(s). This effect lasts for 8s.', 'Pistols born from the strange phenomena in the sky. The forger infused the weapon with the feelings from witnessing the strange star, making it look hollow and light, yet extremely stable, with the power of thunder when it fires.', 33, 412, '6.75%', '30.38%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston\r\n', 'Flawless Phlogiston\r\n', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Ever-changing'),
(254, 'Hollow Mirage', 'Gauntlets', 4, 'ATK%', 'wp_hollow_mirage.png', 'When Resonance Liberation is cast, grants 3 stack(s) of Iron Armor. Each stack increases ATK and DEF by [3, 0.50]%, stacking up to 3 time(s). When the Resonator takes damage, reduces the number of stacks by 1.', 'The Gauntlets born from the strange phenomenon in the sky. The blacksmith infused the feelings of witnessing the strange star into the weapon, making it look hollow and light, but it can exert a tremendous momentum while protecting the user.', 33, 412, '6.75%', '30.38%', 'Cadence Seed\r\n\r\n', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Celestial Blessing'),
(255, 'Comet Flare', 'Rectifier', 4, 'HP%', 'wp_comet_flare.png', 'When dealing Basic Attack DMG or Heavy Attack DMG, increases Healing Bonus by [3, 0.75]%, stacking up to 3 time(s). This effect lasts for 8s and can be triggered 1 time(s) every 0.6s.', 'A Rectifier born born from an aerial phenomenon. Capturing the essence of an alien star, its design is delicate and lightweight, yet it remains sturdy and adaptable.', 33, 412, '6.75%', '30.38%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ringz', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Luminous Protection'),
(256, 'Waning Redshift', 'Broadblade', 4, 'ATK%', 'wp_waning_redshift.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. This broadblade takes its name from the fate of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Intergalactic Gaze'),
(257, 'Endless Collapse', 'Sword', 4, 'ATK%', 'wp_endless_collapse.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. This sword takes its name from the heart of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip\r\n', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Intergalactic Gaze');
INSERT INTO `weapons` (`id`, `name`, `type`, `rarity`, `main_stat`, `image_url`, `description`, `story`, `atk_base`, `atk_max`, `stat_base`, `stat_max`, `mat_1_t1`, `mat_1_t2`, `mat_1_t3`, `mat_1_t4`, `mat_2_t1`, `mat_2_t2`, `mat_2_t3`, `mat_2_t4`, `skill_name`) VALUES
(258, 'Relativistic Jet', 'Pistols', 4, 'ATK%', 'wp_relativistic_jet.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. These pistols take their name from the incessant course of destruction of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston\r\n', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Intergalactic Gaze'),
(259, 'Celestial Spiral', 'Gauntlets', 4, 'ATK%', 'wp_celestial_spiral.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. These gauntlets take their name from the tragic demise of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Intergalactic Gaze'),
(260, 'Fusion Accretion', 'Rectifier', 4, 'ATK%', 'wp_fusion_accretion.png', 'Casting the Resonance Skill grants [6, 1] Resonance Energy and increases ATK by [10, 2.5]%, lasting for 16s. This effect can be triggered once every 20s.', 'A prototype weapon designed by the Black Shores for elite combatants. This rectifier takes its name from the devastating might of a blazar—a galactic nucleus whose blinding radiance pierces the cosmos, shining unmistakably across billions of light years.', 37, 462, '4.05%', '18.23%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Intergalactic Gaze'),
(261, 'Somnoire Anchor', 'Sword', 4, 'ATK%', 'wp_somnoire_anchor.png', 'Gain 1 stack of Hiss when dealing damage to the target, with 1 stack generated every 1s. Hiss: each stack increases the wielder\'s ATK by [2, 0.5]% for 3s, stacking up to 10 times. Switching off the wielder clears all stacks. Gaining 10 stacks increases the wielder\'s Crit. Rate by [6, 1.5]%.', 'An anchor once used by Ivory Gatekeeper to stablize the Somnoire. However, it now looks different ever since Ivory Gatekeeper transformed into a white cat...', 37, 462, '4.05%', '18.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Meow!'),
(262, 'Call of the Abyss', 'Rectifier', 4, ' Energy Regen%', 'wp_call_of_the_abyss.png', 'Casting Resonance Liberation increases the Resonator\'s Healing Bonus by [16, 4]% for 15s.', 'Held by the keepers of this land, this scepter was once a symbol of dominion over its people and the architectural marvels they achieved. However, it has long lost its luster, and its grandeur blends into the ripples of the pipe organ melodies of Rinascita.', 27, 338, '11.52%', '51.84%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Pole of the Celestial Dome'),
(263, 'Meditations on Mercy', 'Broadblade', 4, 'ATK%', 'wp_meditations_on_mercy.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Meditations on Mercy. In the brief pauses between each swing, a warrior wrestles with an inner conflict: to bring down righteous punishment or extend a hand of redemption? Behind every clash of steel is the struggle between wrath and mercy.', 37, 462, '4.05%', '18.23%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Rhetoric'),
(264, 'Fables of Wisdom', 'Sword', 4, 'ATK%', 'wp_fables_of_wisdom.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Fables of Wisdom. A wayfarer once carried this sword, who spun fables of wisdom, passing on insights in the form of witty jests. Keen ears listened to the stories for the truth, while shallow minds heard only amusing punchlines.', 37, 462, '4.05%', '18.23%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Rhetoric'),
(265, 'Romance in Farewell', ' Pistols', 4, 'ATK%', 'wp_romance_in_farewell.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Romance in Farewell. This pistol was once the symbol of the aspiration for repute, the weight of unrequited love, and the tremors of unspoken words. When the trigger is pulled, and the curtain drops, it turns into a long farewell and a sign of lingering sorrow in the heart of the bereaved.', 37, 462, '4.05%', '18.23%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Rhetoric'),
(266, 'Legend of Drunken Hero', 'Gauntlets', 4, 'ATK%', 'wp_legend_of_drunken_hero.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Legend of Drunken Hero. From the cup flows a liquid that grants courage and strength, empowering the hero to defy fate and turn the tide with his gauntlets. Yet in this intoxicating delight lies peril—dulled senses become the hero\'s undoing as enemies close in. Thus, in those wine-stained pages, one always read about triumphs followed by defeats.', 37, 462, '4.05%', '18.23%', 'Cadence Seed', 'Cadence Bud\r\n', 'Cadence Leaf\r\n', 'Cadence Blossom\r\n', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Rhetoric'),
(267, 'Waltz in Masquerade', ' Rectifier', 4, 'ATK%', 'wp_waltz_in_masquerade.png', 'Dealing DMG to enemies with Negative Statuses increases the wielder\'s ATK by [4, 1]% for 10s. This effect can be triggered 1 time per second, stackable up to 4 times.', 'This weapon draws its design inspiration from the play—Waltz in Masquerade. A waltz is a dance of spectacle and masquerade, where the grand symphony drowns whispered secrets and swirling dresses conceal the exchange of letters and promises. The dancers speak a silent language, as smooth and precise as the perfect resonance of a rectifier.', 37, 462, '4.05%', '18.23%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Rhetoric'),
(268, 'Ocean\'s Gift', 'Rectifier', 4, 'ATK%', 'wp_ocean_s_gift.png', 'Dealing DMG to enemies with Spectro Frazzle increases the wielder\'s Spectro DMG by [6, 1]%, gaining 1 stack per second for 6s, stacking up to 4 times.', 'To fishers, the sea is their field of harvest. Harvest means hope.', 37, 462, '4.05%', '18.23%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Fish Catch\r\n'),
(269, 'Aureate Zenith', 'Broadblade', 4, 'Crit DMG%', 'wp_aureate_zenith.png', 'Casting Resonance Liberation increases ATK by [7.2, 3.9]% and grants [10.8, 5.9]% Heavy Attack DMG Bonus for 15s.', 'A Broadblade awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '9.00%', '40.50%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Oath of Tide Hunters'),
(270, 'Feather Edge', ' Sword', 4, ' Crit Rate%', 'wp_feather_edge.png', 'Casting Resonance Liberation increases ATK by [7.2, 3.9]% and grants [10.8, 5.9]% Resonance Liberation DMG Bonus for 15s.', 'A Sword awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '4.50%', '20.25%', 'Inert Metallic Drip', 'Reactive Metallic Drip', 'Polarized Metallic Drip', 'Heterized Metallic Drip', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Oath of Tide Hunters'),
(271, 'Solar Flame', ' Pistols', 4, 'Crit Rate%', 'wp_solar_flame.png', 'Dealing Basic Attack or Heavy Attack DMG increases ATK by [2.2, 1.2]% and grants [2.2, 1.2]% Heavy Attack DMG Bonus for 7s, stacking up to 4 times. This effect can be triggered 1 every 1s.', 'A pair of Pistols awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '4.50%', '20.25%', 'Impure Phlogiston', 'Extracted Phlogiston', 'Refined Phlogiston', 'Flawless Phlogiston', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 'Oath of Tide Hunters'),
(272, 'Aether Strike', 'Gauntlets', 4, 'Crit. DMG%', 'wp_aether_strike.png', 'Casting Resonance Liberation increases ATK by [7.2, 3.9]% and grants [10.8, 5.9]% Resonance Liberation DMG Bonus for 15s.', 'A pair of Gauntlets awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.\r\n', 33, 412, '9.00%', '40.50%', 'Cadence Seed', 'Cadence Bud', 'Cadence Leaf', 'Cadence Blossom', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 'Oath of Tide Hunters'),
(273, 'Radiant Dawn', 'Rectifier', 4, 'Crit DMG%', 'wp_radiant_dawn.png', 'Casting Resonance Skill increases ATK by [9, 4.9]% and grants [9, 4.9]% Basic Attack DMG Bonus for 10s.', 'A Rectifier awarded to Gladiators of exceptional merit. Its engravings draw inspiration from Griffrexes—natural-born hunters and the first allies Septimontians found in this land. Their bond needs no words, radiant and pure, like the blazing sun that watches over all.', 33, 412, '9.00%', '40.50%', 'Lento Helix', 'Adagio Helix', 'Andante Helix', 'Presto Helix', 'Crude Ring', 'Basic Ring', 'Improved Ring\r\n', 'Tailored Ring', 'Oath of Tide Hunters'),
(274, 'Broadblade of Night', 'Broadblade', 3, 'ATK%', 'wp_broadblade_of_night.png', 'When Intro Skill is cast, increases ATK by [8, 2]%, lasting for 10s.', 'May victory prevail the lasting night. In addition to the sworn oath of protection, this broadblade also carries the resolution of those fighting souls.', 26, 325, '5.40%', '24.30%', 'Waveworn Residue 210', 'Waveworn Residue 226', 'Waveworn Residue 235', 'Waveworn Residue 239', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 'Valiance'),
